 1вҶ’import { useState } from "react";
 2вҶ’import { useApp, useInput } from "ink";
 3вҶ’import type { SessionInfo } from "./api.js";
 4вҶ’import { SessionPicker } from "./SessionPicker.js";
 5вҶ’import { MessageView } from "./MessageView.js";
 6вҶ’
 7вҶ’type View = { kind: "picker" } | { kind: "session"; session: SessionInfo };
 8вҶ’
 9вҶ’export function App() {
10вҶ’  const { exit } = useApp();
11вҶ’  const [view, setView] = useState<View>({ kind: "picker" });
12вҶ’
13вҶ’  useInput((input) => {
14вҶ’    if (input === "q" && view.kind === "picker") {
15вҶ’      exit();
16вҶ’    }
17вҶ’  });
18вҶ’
19вҶ’  if (view.kind === "session") {
20вҶ’    return (
21вҶ’      <MessageView sessionPath={view.session.path} onBack={() => setView({ kind: "picker" })} />
22вҶ’    );
23вҶ’  }
24вҶ’
25вҶ’  return <SessionPicker onSelect={(session) => setView({ kind: "session", session })} />;
26вҶ’}
