 1вҶ’/** HTTP API client for the Claude Code Trace backend (port 11423). */
 2вҶ’
 3вҶ’// Types are shared with the main Tauri UI.
 4вҶ’export type {
 5вҶ’  SessionInfo,
 6вҶ’  DisplayMessage,
 7вҶ’  DisplayItem,
 8вҶ’  LoadResult,
 9вҶ’  SessionMeta,
10вҶ’  SessionTotals,
11вҶ’} from "../../shared/types.js";
12вҶ’
13вҶ’import type { SessionInfo, LoadResult } from "../../shared/types.js";
14вҶ’
15вҶ’export interface SettingsResponse {
16вҶ’  projects_dir: string | null;
17вҶ’  default_dir: string;
18вҶ’}
19вҶ’
20вҶ’const API = "http://127.0.0.1:11423";
21вҶ’
22вҶ’async function get<T>(path: string): Promise<T> {
23вҶ’  const res = await fetch(`${API}${path}`);
24вҶ’  if (!res.ok) throw new Error(`API ${path}: ${res.statusText}`);
25вҶ’  return res.json() as Promise<T>;
26вҶ’}
27вҶ’
28вҶ’async function post<T>(path: string, body?: unknown): Promise<T> {
29вҶ’  const res = await fetch(`${API}${path}`, {
30вҶ’    method: "POST",
31вҶ’    headers: { "Content-Type": "application/json" },
32вҶ’    body: body ? JSON.stringify(body) : undefined,
33вҶ’  });
34вҶ’  if (!res.ok) throw new Error(`API ${path}: ${res.statusText}`);
35вҶ’  const text = await res.text();
36вҶ’  return text ? (JSON.parse(text) as T) : (undefined as T);
37вҶ’}
38вҶ’
39вҶ’export const api = {
40вҶ’  getSettings: () => get<SettingsResponse>("/api/settings"),
41вҶ’  getProjectDirs: () => get<string[]>("/api/project-dirs"),
42вҶ’  discoverSessions: (dirs: string[]) =>
43вҶ’    get<SessionInfo[]>(`/api/sessions?dirs=${encodeURIComponent(dirs.join(","))}`),
44вҶ’  loadSession: (path: string) => post<LoadResult>("/api/session/load", { path }),
45вҶ’  watchSession: (path: string) => post<void>("/api/session/watch", { path }),
46вҶ’  unwatchSession: () => post<void>("/api/session/unwatch"),
47вҶ’};
