  1вҶ’import { useState, useEffect } from "react";
  2вҶ’import { Box, Text, useInput } from "ink";
  3вҶ’import { Spinner } from "@inkjs/ui";
  4вҶ’import { api, type SessionInfo } from "./api.js";
  5вҶ’import { formatTokens, formatCost, timeAgo, truncate } from "../../shared/format.js";
  6вҶ’
  7вҶ’interface SessionPickerProps {
  8вҶ’  onSelect: (session: SessionInfo) => void;
  9вҶ’}
 10вҶ’
 11вҶ’export function SessionPicker({ onSelect }: SessionPickerProps) {
 12вҶ’  const [sessions, setSessions] = useState<SessionInfo[]>([]);
 13вҶ’  const [loading, setLoading] = useState(true);
 14вҶ’  const [selected, setSelected] = useState(0);
 15вҶ’  const [error, setError] = useState("");
 16вҶ’
 17вҶ’  useEffect(() => {
 18вҶ’    (async () => {
 19вҶ’      try {
 20вҶ’        const dirs = await api.getProjectDirs();
 21вҶ’        if (dirs.length === 0) {
 22вҶ’          setError("No project directories found. Run the desktop app first to configure.");
 23вҶ’          setLoading(false);
 24вҶ’          return;
 25вҶ’        }
 26вҶ’        const list = await api.discoverSessions(dirs);
 27вҶ’        setSessions(list);
 28вҶ’      } catch (e) {
 29вҶ’        setError(`Cannot connect to backend. Is the app running?\n${e}`);
 30вҶ’      }
 31вҶ’      setLoading(false);
 32вҶ’    })();
 33вҶ’  }, []);
 34вҶ’
 35вҶ’  useInput((input, key) => {
 36вҶ’    if (loading || sessions.length === 0) return;
 37вҶ’    if (input === "j" || key.downArrow) {
 38вҶ’      setSelected((i) => Math.min(i + 1, sessions.length - 1));
 39вҶ’    } else if (input === "k" || key.upArrow) {
 40вҶ’      setSelected((i) => Math.max(i - 1, 0));
 41вҶ’    } else if (key.return) {
 42вҶ’      onSelect(sessions[selected]);
 43вҶ’    }
 44вҶ’  });
 45вҶ’
 46вҶ’  if (loading) {
 47вҶ’    return (
 48вҶ’      <Box padding={1}>
 49вҶ’        <Spinner label="Discovering sessions..." />
 50вҶ’      </Box>
 51вҶ’    );
 52вҶ’  }
 53вҶ’
 54вҶ’  if (error) {
 55вҶ’    return (
 56вҶ’      <Box padding={1}>
 57вҶ’        <Text color="red">{error}</Text>
 58вҶ’      </Box>
 59вҶ’    );
 60вҶ’  }
 61вҶ’
 62вҶ’  // Show a window of sessions around the selection
 63вҶ’  const windowSize = process.stdout.rows ? process.stdout.rows - 4 : 20;
 64вҶ’  const half = Math.floor(windowSize / 2);
 65вҶ’  let start = Math.max(0, selected - half);
 66вҶ’  const end = Math.min(sessions.length, start + windowSize);
 67вҶ’  if (end - start < windowSize) start = Math.max(0, end - windowSize);
 68вҶ’  const visible = sessions.slice(start, end);
 69вҶ’
 70вҶ’  return (
 71вҶ’    <Box flexDirection="column" padding={1}>
 72вҶ’      <Box marginBottom={1}>
 73вҶ’        <Text bold>Sessions ({sessions.length}) вҖ” j/k navigate, Enter open, q quit</Text>
 74вҶ’      </Box>
 75вҶ’      {visible.map((s, i) => {
 76вҶ’        const idx = start + i;
 77вҶ’        const isSelected = idx === selected;
 78вҶ’        return (
 79вҶ’          <Box key={s.path}>
 80вҶ’            <Text color={isSelected ? "blue" : undefined} bold={isSelected} inverse={isSelected}>
 81вҶ’              {isSelected ? " в–ё " : "   "}
 82вҶ’              {s.is_ongoing ? "в—Ҹ " : "  "}
 83вҶ’              <Text dimColor={!isSelected}>{truncate(s.first_message || s.session_id, 50)}</Text>
 84вҶ’              <Text dimColor> {formatTokens(s.total_tokens)} tok</Text>
 85вҶ’              <Text dimColor color="yellow">
 86вҶ’                {" "}
 87вҶ’                {formatCost(s.cost_usd)}
 88вҶ’              </Text>
 89вҶ’              <Text dimColor> {timeAgo(s.mod_time)}</Text>
 90вҶ’              {s.model ? (
 91вҶ’                <Text dimColor color="cyan">
 92вҶ’                  {" "}
 93вҶ’                  {s.model.split("-")[0]}
 94вҶ’                </Text>
 95вҶ’              ) : null}
 96вҶ’            </Text>
 97вҶ’          </Box>
 98вҶ’        );
 99вҶ’      })}
100вҶ’    </Box>
101вҶ’  );
102вҶ’}
103вҶ’

  1вҶ’import { useState, useEffect, useCallback } from "react";
  2вҶ’import { Box, Text, useInput } from "ink";
  3вҶ’import { Spinner } from "@inkjs/ui";
  4вҶ’import { api, type DisplayMessage } from "./api.js";
  5вҶ’import { useSSE } from "./useSSE.js";
  6вҶ’import { formatTokens, formatDuration, truncate } from "../../shared/format.js";
  7вҶ’
  8вҶ’interface MessageViewProps {
  9вҶ’  sessionPath: string;
 10вҶ’  onBack: () => void;
 11вҶ’}
 12вҶ’
 13вҶ’function roleColor(role: string): string {
 14вҶ’  switch (role) {
 15вҶ’    case "claude":
 16вҶ’      return "magenta";
 17вҶ’    case "user":
 18вҶ’      return "green";
 19вҶ’    case "system":
 20вҶ’      return "yellow";
 21вҶ’    default:
 22вҶ’      return "white";
 23вҶ’  }
 24вҶ’}
 25вҶ’
 26вҶ’function roleIcon(role: string): string {
 27вҶ’  switch (role) {
 28вҶ’    case "claude":
 29вҶ’      return "рҹӨ–";
 30вҶ’    case "user":
 31вҶ’      return "рҹ‘Ө";
 32вҶ’    case "system":
 33вҶ’      return "вҡҷпёҸ";
 34вҶ’    default:
 35вҶ’      return "  ";
 36вҶ’  }
 37вҶ’}
 38вҶ’
 39вҶ’export function MessageView({ sessionPath, onBack }: MessageViewProps) {
 40вҶ’  const [messages, setMessages] = useState<DisplayMessage[]>([]);
 41вҶ’  const [ongoing, setOngoing] = useState(false);
 42вҶ’  const [meta, setMeta] = useState({ cwd: "", git_branch: "", permission_mode: "" });
 43вҶ’  const [totals, setTotals] = useState({ total_tokens: 0, cost_usd: 0, model: "" });
 44вҶ’  const [loading, setLoading] = useState(true);
 45вҶ’  const [selected, setSelected] = useState(0);
 46вҶ’  const [expanded, setExpanded] = useState<Set<number>>(new Set());
 47вҶ’
 48вҶ’  useEffect(() => {
 49вҶ’    (async () => {
 50вҶ’      try {
 51вҶ’        const result = await api.loadSession(sessionPath);
 52вҶ’        setMessages(result.messages);
 53вҶ’        setOngoing(result.ongoing);
 54вҶ’        setMeta(result.meta);
 55вҶ’        setTotals(result.session_totals);
 56вҶ’        setSelected(result.messages.length - 1);
 57вҶ’        await api.watchSession(sessionPath);
 58вҶ’      } catch {
 59вҶ’        // ignore
 60вҶ’      }
 61вҶ’      setLoading(false);
 62вҶ’    })();
 63вҶ’    return () => {
 64вҶ’      api.unwatchSession().catch(() => {});
 65вҶ’    };
 66вҶ’  }, [sessionPath]);
 67вҶ’
 68вҶ’  // Live updates via SSE
 69вҶ’  useSSE<{
 70вҶ’    messages: DisplayMessage[];
 71вҶ’    ongoing: boolean;
 72вҶ’    permission_mode: string;
 73вҶ’    session_totals: { total_tokens: number; cost_usd: number; model: string };
 74вҶ’  }>(
 75вҶ’    "session-update",
 76вҶ’    useCallback((payload) => {
 77вҶ’      setMessages(payload.messages);
 78вҶ’      setOngoing(payload.ongoing);
 79вҶ’      setTotals(payload.session_totals);
 80вҶ’      if (payload.permission_mode) {
 81вҶ’        setMeta((m) => ({ ...m, permission_mode: payload.permission_mode }));
 82вҶ’      }
 83вҶ’    }, []),
 84вҶ’  );
 85вҶ’
 86вҶ’  const toggle = useCallback((idx: number) => {
 87вҶ’    setExpanded((prev) => {
 88вҶ’      const next = new Set(prev);
 89вҶ’      if (next.has(idx)) next.delete(idx);
 90вҶ’      else next.add(idx);
 91вҶ’      return next;
 92вҶ’    });
 93вҶ’  }, []);
 94вҶ’
 95вҶ’  useInput((input, key) => {
 96вҶ’    if (input === "q" || key.escape) {
 97вҶ’      onBack();
 98вҶ’    } else if (input === "j" || key.downArrow) {
 99вҶ’      setSelected((i) => Math.min(i + 1, messages.length - 1));
100вҶ’    } else if (input === "k" || key.upArrow) {
101вҶ’      setSelected((i) => Math.max(i - 1, 0));
102вҶ’    } else if (key.tab) {
103вҶ’      toggle(selected);
104вҶ’    } else if (input === "e") {
105вҶ’      // Expand all Claude messages
106вҶ’      const all = new Set<number>();
107вҶ’      messages.forEach((m, i) => {
108вҶ’        if (m.role === "claude") all.add(i);
109вҶ’      });
110вҶ’      setExpanded(all);
111вҶ’    } else if (input === "c") {
112вҶ’      setExpanded(new Set());
113вҶ’    } else if (input === "G") {
114вҶ’      setSelected(messages.length - 1);
115вҶ’    } else if (input === "g") {
116вҶ’      setSelected(0);
117вҶ’    }
118вҶ’  });
119вҶ’
120вҶ’  if (loading) {
121вҶ’    return (
122вҶ’      <Box padding={1}>
123вҶ’        <Spinner label="Loading session..." />
124вҶ’      </Box>
125вҶ’    );
126вҶ’  }
127вҶ’
128вҶ’  const cols = process.stdout.columns || 80;
129вҶ’  const windowSize = (process.stdout.rows || 24) - 6;
130вҶ’
131вҶ’  // Info bar
132вҶ’  const projectName = meta.cwd.split("/").pop() || "";
133вҶ’  const branch = meta.git_branch || "";
134вҶ’
135вҶ’  // Window around selection
136вҶ’  let start = Math.max(0, selected - Math.floor(windowSize / 2));
137вҶ’  const end = Math.min(messages.length, start + windowSize);
138вҶ’  if (end - start < windowSize) start = Math.max(0, end - windowSize);
139вҶ’  const visible = messages.slice(start, end);
140вҶ’
141вҶ’  return (
142вҶ’    <Box flexDirection="column">
143вҶ’      {/* Info bar */}
144вҶ’      <Box paddingX={1} gap={2}>
145вҶ’        <Text bold color="cyan">
146вҶ’          {projectName}
147вҶ’        </Text>
148вҶ’        {branch ? <Text dimColor>{branch}</Text> : null}
149вҶ’        <Text dimColor>{formatTokens(totals.total_tokens)} tok</Text>
150вҶ’        <Text dimColor color="yellow">
151вҶ’          ${totals.cost_usd.toFixed(2)}
152вҶ’        </Text>
153вҶ’        {ongoing ? (
154вҶ’          <Text color="green" bold>
155вҶ’            {" "}
156вҶ’            в—Ҹ active
157вҶ’          </Text>
158вҶ’        ) : null}
159вҶ’      </Box>
160вҶ’
161вҶ’      {/* Messages */}
162вҶ’      <Box flexDirection="column" paddingX={1}>
163вҶ’        {visible.map((msg, i) => {
164вҶ’          const idx = start + i;
165вҶ’          const isSelected = idx === selected;
166вҶ’          const isExpanded = expanded.has(idx);
167вҶ’          const contentWidth = cols - 12;
168вҶ’
169вҶ’          return (
170вҶ’            <Box key={idx} flexDirection="column">
171вҶ’              <Box>
172вҶ’                <Text inverse={isSelected} bold={isSelected} color={roleColor(msg.role)}>
173вҶ’                  {isSelected ? "в–ё" : " "}
174вҶ’                  {roleIcon(msg.role)} {msg.role.padEnd(7)}
175вҶ’                </Text>
176вҶ’                <Text dimColor={!isSelected}> {truncate(msg.content, contentWidth - 30)}</Text>
177вҶ’                {msg.tool_call_count > 0 && (
178вҶ’                  <Text dimColor color="yellow">
179вҶ’                    {" "}
180вҶ’                    вҡҷ{msg.tool_call_count}
181вҶ’                  </Text>
182вҶ’                )}
183вҶ’                {msg.tokens_raw > 0 && <Text dimColor> {formatTokens(msg.tokens_raw)}</Text>}
184вҶ’                {msg.duration_ms > 0 && <Text dimColor> {formatDuration(msg.duration_ms)}</Text>}
185вҶ’              </Box>
186вҶ’
187вҶ’              {/* Expanded: show items */}
188вҶ’              {isExpanded && msg.items.length > 0 && (
189вҶ’                <Box flexDirection="column" paddingLeft={4} marginBottom={1}>
190вҶ’                  {msg.items.map((item) => (
191вҶ’                    <Box key={`${item.item_type}-${item.tool_name || item.text.slice(0, 20)}`}>
192вҶ’                      <Text dimColor>
193вҶ’                        {item.item_type === "ToolCall" ? (
194вҶ’                          <Text color={item.tool_error ? "red" : "blue"}>
195вҶ’                            вҡҷ {item.tool_name}
196вҶ’                            {item.tool_summary
197вҶ’                              ? ` вҖ” ${truncate(item.tool_summary, contentWidth - 20)}`
198вҶ’                              : ""}
199вҶ’                          </Text>
200вҶ’                        ) : item.item_type === "Thinking" ? (
201вҶ’                          <Text color="gray">рҹ’ӯ {truncate(item.text, contentWidth - 10)}</Text>
202вҶ’                        ) : item.item_type === "Output" ? (
203вҶ’                          <Text>{truncate(item.text, contentWidth - 10)}</Text>
204вҶ’                        ) : (
205вҶ’                          <Text color="gray">
206вҶ’                            {item.item_type}: {truncate(item.text, contentWidth - 20)}
207вҶ’                          </Text>
208вҶ’                        )}
209вҶ’                      </Text>
210вҶ’                    </Box>
211вҶ’                  ))}
212вҶ’                </Box>
213вҶ’              )}
214вҶ’            </Box>
215вҶ’          );
216вҶ’        })}
217вҶ’      </Box>
218вҶ’
219вҶ’      {/* Status bar */}
220вҶ’      <Box paddingX={1} gap={2}>
221вҶ’        <Text dimColor>
222вҶ’          j/k nav Tab expand e/c all G/g jump q back {selected + 1}/{messages.length}
223вҶ’        </Text>
224вҶ’      </Box>
225вҶ’    </Box>
226вҶ’  );
227вҶ’}
