 9вҶ’  const anchor = (e.target as HTMLElement).closest("a");
10вҶ’  if (!anchor) return;
11вҶ’  const href = anchor.getAttribute("href");
12вҶ’  if (href && (href.startsWith("http://") || href.startsWith("https://"))) {
13вҶ’    e.preventDefault();
14вҶ’    openUrl(href);
15вҶ’  }
16вҶ’});
17вҶ’
18вҶ’const rootEl = document.getElementById("root");
19вҶ’if (!rootEl) throw new Error("Missing #root element");
20вҶ’
21вҶ’createRoot(rootEl).render(
22вҶ’  <StrictMode>
23вҶ’    <App />
24вҶ’  </StrictMode>,
25вҶ’);
