 20вҶ’
 21вҶ’export function App() {
 22вҶ’  const [view, setView] = useState<ViewState>("picker");
 23вҶ’  const [selectedMessage, setSelectedMessage] = useState(0);
 24вҶ’  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 25вҶ’  const [showKeybinds, setShowKeybinds] = useState(true);
 26вҶ’  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 27вҶ’  const [sidebarWidth, setSidebarWidth] = useState(180);
 28вҶ’  const [sidebarFocused, setSidebarFocused] = useState(false);
 29вҶ’  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 30вҶ’  const [showSettings, setShowSettings] = useState(false);
 31вҶ’
 32вҶ’  const handleSelectProject = useCallback(
 33вҶ’    (project: string | null) => {
 34вҶ’      setSelectedProject(project);
 35вҶ’      setPickerSelectedIndex(0);
 36вҶ’      setSidebarFocused(false);
 37вҶ’      if (view !== "picker") setView("picker");
 38вҶ’    },
 39вҶ’    [view],
 40вҶ’  );
 41вҶ’
 42вҶ’  const session = useSession();
 43вҶ’  const picker = usePicker(selectedProject);
