 1вҶ’/**
 2вҶ’ * Pure formatting utilities shared between Tauri UI and TUI.
 3вҶ’ * No React, DOM, or framework dependencies.
 4вҶ’ */
 5вҶ’
 6вҶ’/** Formats a token count: 1234 -> "1.2k", 1234567 -> "1.2M" */
 7вҶ’export function formatTokens(n: number): string {
 8вҶ’  if (n >= 1_000_000) return (n / 1_000_000).toFixed(1) + "M";
 9вҶ’  if (n >= 1_000) return (n / 1_000).toFixed(1) + "k";
10вҶ’  return String(n);
11вҶ’}
12вҶ’
13вҶ’/** Formats USD cost: 1.5 -> "$1.50" */
14вҶ’export function formatCost(usd: number): string {
15вҶ’  return "$" + usd.toFixed(2);
16вҶ’}
17вҶ’
18вҶ’/** Formats duration: 1500 -> "1.5s", 90000 -> "1m 30s" */
19вҶ’export function formatDuration(ms: number): string {
20вҶ’  if (ms < 1000) return `${ms}ms`;
21вҶ’  const s = ms / 1000;
22вҶ’  if (s < 60) return `${s.toFixed(1)}s`;
23вҶ’  const m = Math.floor(s / 60);
24вҶ’  const rem = Math.floor(s % 60);
25вҶ’  return rem > 0 ? `${m}m ${rem}s` : `${m}m`;
26вҶ’}
27вҶ’
28вҶ’/** Truncate string to max length with ellipsis, collapsing newlines. */
29вҶ’export function truncate(s: string, max: number): string {
30вҶ’  const line = s.replace(/\n/g, " ").trim();
