  8вҶ’interface MessageListProps {
  9вҶ’  messages: DisplayMessage[];
 10вҶ’  selectedIndex: number;
 11вҶ’  expandedSet: Set<number>;
 12вҶ’  ongoing: boolean;
 13вҶ’  onSelect: (index: number) => void;
 14вҶ’  onToggle: (index: number) => void;
 15вҶ’  onOpenDetail: (index: number) => void;
 16вҶ’  viewActionsRef: ViewActionsRef;
 17вҶ’  onExpandAll: () => void;
