 21вҶ’export function MessageList({
 22вҶ’  messages,
 23вҶ’  selectedIndex,
 24вҶ’  expandedSet,
 25вҶ’  ongoing,
 26вҶ’  onSelect,
 27вҶ’  onToggle,
 28вҶ’  onOpenDetail,
 29вҶ’  viewActionsRef,
 30вҶ’  onExpandAll,
 31вҶ’  onCollapseAll,
 32вҶ’}: MessageListProps) {
 33вҶ’  useRegisterViewActions(viewActionsRef, { expandAll: onExpandAll, collapseAll: onCollapseAll });
 34вҶ’  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
 35вҶ’  const selectedRef = useScrollToSelected(selectedIndex);
 36вҶ’
 37вҶ’  const handleClick = useCallback(
 38вҶ’    (index: number) => {
 39вҶ’      if (selectedIndex === index) {
 40вҶ’        onToggle(index);
 41вҶ’      } else {
 42вҶ’        onSelect(index);
 43вҶ’      }
 44вҶ’    },
 45вҶ’    [selectedIndex, onSelect, onToggle],
 46вҶ’  );
 47вҶ’
 48вҶ’  // Chronological order: oldest messages first
 49вҶ’  const ordered = useMemo(() => {
 50вҶ’    const indices: number[] = [];
 51вҶ’    for (let i = 0; i < messages.length; i++) {
 52вҶ’      indices.push(i);
 53вҶ’    }
 54вҶ’    return indices;
 55вҶ’  }, [messages.length]);
 56вҶ’
 57вҶ’  if (messages.length === 0) {
 58вҶ’    return (
 59вҶ’      <div className="message-list">
 60вҶ’        <div className="message-list__empty">No messages loaded</div>
 61вҶ’      </div>
 62вҶ’    );
 63вҶ’  }
 64вҶ’
 65вҶ’  return (
 66вҶ’    <div className="message-list" ref={listRef}>
 67вҶ’      {ordered.map((i) => {
 68вҶ’        const msg = messages[i];
 69вҶ’        if (msg.role === "compact") {
 70вҶ’          return <CompactSeparator key={i} content={msg.content} />;
 71вҶ’        }
 72вҶ’
 73вҶ’        const isSelected = i === selectedIndex;
 74вҶ’        const isLast = i === messages.length - 1;
 75вҶ’
 76вҶ’        return (
 77вҶ’          <MessageItem
 78вҶ’            key={i}
 79вҶ’            ref={isSelected ? selectedRef : undefined}
 80вҶ’            message={msg}
 81вҶ’            index={i}
 82вҶ’            isSelected={isSelected}
 83вҶ’            isExpanded={expandedSet.has(i)}
 84вҶ’            onClick={handleClick}
 85вҶ’            onOpenDetail={onOpenDetail}
 86вҶ’            isOngoing={isLast && ongoing}
 87вҶ’          />
 88вҶ’        );
 89вҶ’      })}
 90вҶ’    </div>
 91вҶ’  );
 92вҶ’}
