 32вҶ’
 33вҶ’  static fromSessions(sessions: SessionInfo[]): ProjectNode[] {
 34вҶ’    const map = new Map<string, ProjectNode>();
 35вҶ’    for (const s of sessions) {
 36вҶ’      const key = projectKey(s.path);
 37вҶ’      const existing = map.get(key);
 38вҶ’      if (existing) {
