 59вҶ’
 60вҶ’  /** Short label relative to a parent key. */
 61вҶ’  static childLabel(parentKey: string, childKey: string): string {
 62вҶ’    return childKey.slice(parentKey.length).replace(/^-+/, "") || projectDisplayName(childKey);
