 70вҶ’
 71вҶ’    for (const node of sorted) {
 72вҶ’      let parent: TreeNode | undefined;
 73вҶ’      for (const candidate of all) {
 74вҶ’        if (
 75вҶ’          node.key.startsWith(candidate.node.key + "-") &&
 76вҶ’          (!parent || candidate.node.key.length > parent.node.key.length)
 77вҶ’        ) {
 78вҶ’          parent = candidate;
 79вҶ’        }
 80вҶ’      }
 81вҶ’
 82вҶ’      const tn = new TreeNode(node);
 83вҶ’      all.push(tn);
 84вҶ’
 85вҶ’      if (parent) {
 86вҶ’        tn.node = new ProjectNode(
 87вҶ’          TreeNode.childLabel(parent.node.key, node.key),
 88вҶ’          node.key,
 89вҶ’          node.sessionCount,
 90вҶ’          node.hasOngoing,
 91вҶ’        );
 92вҶ’        parent.children.push(tn);
 93вҶ’      } else {
 94вҶ’        roots.push(tn);
 95вҶ’      }
 96вҶ’    }
 97вҶ’
 98вҶ’    roots.sort(TreeNode.cmp);
 99вҶ’    for (const r of all) r.children.sort(TreeNode.cmp);
100вҶ’    return roots;
101вҶ’  }
102вҶ’}
