104вҶ’type WorktreeKind = "worktrees" | "claude-worktrees";
105вҶ’
106вҶ’class FlatItem {
107вҶ’  constructor(
108вҶ’    public key: string | null,
109вҶ’    public name: string,
110вҶ’    public count: number,
111вҶ’    public ongoing: boolean,
112вҶ’    public depth: number,
113вҶ’    public isGroup: boolean,
114вҶ’  ) {}
115вҶ’
116вҶ’  static detectWorktreeKind(parentKey: string, childKey: string): WorktreeKind | null {
117вҶ’    const rest = childKey.slice(parentKey.length);
118вҶ’    if (rest.startsWith("--claude-worktrees-")) return "claude-worktrees";
119вҶ’    if (rest.startsWith("-worktrees-")) return "worktrees";
120вҶ’    return null;
121вҶ’  }
122вҶ’
123вҶ’  static worktreeLeafName(parentKey: string, childKey: string, kind: WorktreeKind): string {
124вҶ’    const prefixLen =
125вҶ’      kind === "claude-worktrees" ? "--claude-worktrees-".length : "-worktrees-".length;
126вҶ’    return (
127вҶ’      childKey.slice(parentKey.length + prefixLen).replace(/^-+/, "") ||
128вҶ’      projectDisplayName(childKey)
129вҶ’    );
130вҶ’  }
131вҶ’
132вҶ’  static fromTree(roots: TreeNode[]): FlatItem[] {
133вҶ’    const items: FlatItem[] = [];
134вҶ’
135вҶ’    function walk(nodes: TreeNode[], depth: number, parentKey: string | null) {
136вҶ’      for (const tn of nodes) {
137вҶ’        items.push(
138вҶ’          new FlatItem(
139вҶ’            tn.node.key,
140вҶ’            tn.node.name,
141вҶ’            tn.node.sessionCount,
142вҶ’            tn.node.hasOngoing,
143вҶ’            depth,
144вҶ’            false,
145вҶ’          ),
146вҶ’        );
147вҶ’
148вҶ’        // Categorise children into worktree groups and regular
149вҶ’        const groups = new Map<WorktreeKind, TreeNode[]>();
150вҶ’        const regular: TreeNode[] = [];
151вҶ’        for (const child of tn.children) {
152вҶ’          const kind =
153вҶ’            parentKey !== null || depth === 0
154вҶ’              ? FlatItem.detectWorktreeKind(tn.node.key, child.node.key)
155вҶ’              : null;
156вҶ’          if (kind) {
157вҶ’            let list = groups.get(kind);
158вҶ’            if (!list) {
159вҶ’              list = [];
160вҶ’              groups.set(kind, list);
161вҶ’            }
162вҶ’            list.push(child);
163вҶ’          } else {
164вҶ’            regular.push(child);
165вҶ’          }
166вҶ’        }
167вҶ’
168вҶ’        // Emit worktree group headers + their children
169вҶ’        for (const [kind, children] of groups) {
170вҶ’          const totalCount = children.reduce((s, c) => s + c.node.sessionCount, 0);
171вҶ’          const anyOngoing = children.some((c) => c.node.hasOngoing);
172вҶ’          items.push(
173вҶ’            new FlatItem(
174вҶ’              `__group:${kind}:${tn.node.key}`,
175вҶ’              kind,
176вҶ’              totalCount,
177вҶ’              anyOngoing,
178вҶ’              depth + 1,
179вҶ’              true,
180вҶ’            ),
181вҶ’          );
182вҶ’          for (const child of children) {
183вҶ’            items.push(
184вҶ’              new FlatItem(
185вҶ’                child.node.key,
186вҶ’                FlatItem.worktreeLeafName(tn.node.key, child.node.key, kind),
187вҶ’                child.node.sessionCount,
188вҶ’                child.node.hasOngoing,
189вҶ’                depth + 2,
190вҶ’                false,
191вҶ’              ),
192вҶ’            );
193вҶ’            walk(child.children, depth + 3, child.node.key);
194вҶ’          }
195вҶ’        }
196вҶ’
197вҶ’        walk(regular, depth + 1, tn.node.key);
198вҶ’      }
199вҶ’    }
200вҶ’
201вҶ’    walk(roots, 0, null);
202вҶ’    return items;
203вҶ’  }
204вҶ’}
205вҶ’
206вҶ’/**
207вҶ’ * Returns the ordered list of selectable keys as displayed in the tree.
208вҶ’ * Index 0 = null ("All Projects"), then project keys and group keys in tree order.
209вҶ’ */
210вҶ’export function useProjectKeys(sessions: SessionInfo[]): (string | null)[] {
211вҶ’  return useMemo(() => {
212вҶ’    const nodes = ProjectNode.fromSessions(sessions);
213вҶ’    const tree = TreeNode.buildTree(nodes);
214вҶ’    const flat = FlatItem.fromTree(tree);
215вҶ’    return [null, ...flat.map((f) => f.key)];
216вҶ’  }, [sessions]);
217вҶ’}
