233вҶ’    return FlatItem.fromTree(tree);
234вҶ’  }, [sessions]);
235вҶ’
236вҶ’  const scrollRef = useScrollToSelected(highlightedIndex);
237вҶ’
238вҶ’  const allItems: FlatItem[] = [
239вҶ’    {
240вҶ’      key: null,
241вҶ’      name: "All Projects",
242вҶ’      count: sessions.length,
243вҶ’      ongoing: false,
244вҶ’      depth: 0,
245вҶ’      isGroup: false,
246вҶ’    },
