272вҶ’          const isHighlighted = isFocused && idx === highlightedIndex;
273вҶ’          return (
274вҶ’            <div
275вҶ’              key={item.key ?? "__all__"}
276вҶ’              ref={isHighlighted ? scrollRef : undefined}
