278вҶ’              style={item.depth > 0 ? { paddingLeft: 12 + item.depth * 16 } : undefined}
279вҶ’              onClick={item.isGroup ? undefined : () => onSelectProject(item.key)}
280вҶ’            >
281вҶ’              <span
282вҶ’                className="project-tree__name"
283вҶ’                title={item.isGroup ? undefined : (item.key ?? undefined)}
284вҶ’              >
285вҶ’                {item.depth > 0 && <span className="project-tree__branch">{"\u2514"} </span>}
286вҶ’                {item.isGroup && (
287вҶ’                  <span className="project-tree__group-icon">
288вҶ’                    {item.name === "worktrees" ? <GitBranchIcon /> : <GitMergeIcon />}
289вҶ’                  </span>
290вҶ’                )}
291вҶ’                {item.name}
292вҶ’              </span>
293вҶ’              <span className="project-tree__meta">
294вҶ’                {item.ongoing && <OngoingDots count={1} />}
295вҶ’                <span className="project-tree__count">{item.count}</span>
296вҶ’              </span>
297вҶ’            </div>
298вҶ’          );
299вҶ’        })}
300вҶ’      </div>
301вҶ’    </div>
