 19вҶ’/* в”Җв”Җв”Җ Helpers в”Җв”Җв”Җ */
 20вҶ’
 21вҶ’/** Recursively find a DisplayItem by agent_id in a nested item tree. */
 22вҶ’function findItemByAgentId(items: DisplayItem[], agentId: string): DisplayItem | undefined {
 23вҶ’  for (const item of items) {
 24вҶ’    if (item.agent_id === agentId) return item;
 25вҶ’    for (const subMsg of item.subagent_messages) {
 26вҶ’      const found = findItemByAgentId(subMsg.items, agentId);
 27вҶ’      if (found) return found;
 28вҶ’    }
 29вҶ’  }
 30вҶ’  return undefined;
 31вҶ’}
 32вҶ’
 33вҶ’/* в”Җв”Җв”Җ Panel stack types в”Җв”Җв”Җ */
 34вҶ’
 35вҶ’type PanelEntry =
 36вҶ’  | { kind: "agent-list"; item: DisplayItem; key: string }
 37вҶ’  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 38вҶ’
 39вҶ’/** Imperative handle exposed by each navigable column */
 40вҶ’interface ColumnNav {
 41вҶ’  moveUp: () => void;
 42вҶ’  moveDown: () => void;
 43вҶ’  toggle: () => void;
 44вҶ’  enter: () => void;
 45вҶ’  itemCount: () => number;
 46вҶ’  expandAll: () => void;
 47вҶ’  collapseAll: () => void;
 48вҶ’}
 49вҶ’
 50вҶ’interface MessageDetailProps {
 51вҶ’  message: DisplayMessage;
 52вҶ’  ongoing?: boolean;
 53вҶ’  onBack: () => void;
 54вҶ’  viewActionsRef: ViewActionsRef;
 55вҶ’}
 56вҶ’
 57вҶ’export function MessageDetail({
 58вҶ’  message: msg,
 59вҶ’  ongoing,
 60вҶ’  onBack,
 61вҶ’  viewActionsRef,
 62вҶ’}: MessageDetailProps) {
 63вҶ’  const {
 64вҶ’    set: expandedItems,
 65вҶ’    toggle: toggleItem,
 66вҶ’    addAll: expandAllItems,
 67вҶ’    clear: clearItems,
 68вҶ’  } = useToggleSet();
 69вҶ’  const [selectedItem, setSelectedItem] = useState(0);
 70вҶ’  const scrollRef = useScrollToSelected(selectedItem);
 71вҶ’  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 72вҶ’  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 73вҶ’  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 74вҶ’  const bodyRef = useRef<HTMLDivElement>(null);
 75вҶ’  useAutoScroll(msg.items.length, bodyRef);
 76вҶ’  const savedScroll = useRef<number | null>(null);
 77вҶ’  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 78вҶ’
 79вҶ’  const detailExpandAll = useCallback(() => {
 80вҶ’    if (focusedColumn === 0) {
 81вҶ’      expandAllItems(msg.items.map((_, i) => i));
 82вҶ’    } else {
 83вҶ’      panelRefs.current.get(focusedColumn - 1)?.expandAll();
 84вҶ’    }
 85вҶ’  }, [msg.items, expandAllItems, focusedColumn]);
 86вҶ’
 87вҶ’  const detailCollapseAll = useCallback(() => {
 88вҶ’    if (focusedColumn === 0) {
 89вҶ’      clearItems();
 90вҶ’    } else {
 91вҶ’      panelRefs.current.get(focusedColumn - 1)?.collapseAll();
 92вҶ’    }
 93вҶ’  }, [clearItems, focusedColumn]);
 94вҶ’
 95вҶ’  useRegisterViewActions(viewActionsRef, {
 96вҶ’    expandAll: detailExpandAll,
 97вҶ’    collapseAll: detailCollapseAll,
 98вҶ’  });
 99вҶ’
100вҶ’  // Keep panel stack items fresh when the session watcher sends updated data.
101вҶ’  // Without this, subagent_ongoing and subagent_messages would be stale.
102вҶ’  // Only updates state when something meaningful changed to avoid extra re-renders.
103вҶ’  useEffect(() => {
104вҶ’    if (panelStack.length === 0) return;
105вҶ’    setPanelStack((prev) => {
106вҶ’      let changed = false;
107вҶ’      const next = prev.map((entry) => {
108вҶ’        if (!entry.item.agent_id) return entry;
109вҶ’        const fresh = findItemByAgentId(msg.items, entry.item.agent_id);
110вҶ’        if (!fresh) return entry;
111вҶ’        // Skip if nothing meaningful changed.
112вҶ’        if (
113вҶ’          fresh.subagent_ongoing === entry.item.subagent_ongoing &&
114вҶ’          fresh.subagent_messages.length === entry.item.subagent_messages.length
115вҶ’        ) {
116вҶ’          return entry;
117вҶ’        }
118вҶ’        changed = true;
119вҶ’        if (entry.kind === "agent-list") {
120вҶ’          return { ...entry, item: fresh };
121вҶ’        }
122вҶ’        // For agent-detail, also refresh the message by matching timestamp.
123вҶ’        const freshMsg =
124вҶ’          fresh.subagent_messages.find(
125вҶ’            (m) => m.timestamp === entry.msg.timestamp && m.role === entry.msg.role,
126вҶ’          ) ?? entry.msg;
127вҶ’        return { ...entry, item: fresh, msg: freshMsg };
128вҶ’      });
129вҶ’      return changed ? next : prev;
130вҶ’    });
131вҶ’  }, [msg.items, panelStack.length]);
132вҶ’
133вҶ’  useLayoutEffect(() => {
134вҶ’    if (savedScroll.current != null && bodyRef.current) {
135вҶ’      bodyRef.current.scrollTop = savedScroll.current;
136вҶ’      savedScroll.current = null;
137вҶ’    }
138вҶ’  }, [panelStack.length]);
139вҶ’
140вҶ’  const model = msg.model ? shortModel(msg.model) : "";
141вҶ’  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
142вҶ’  const time = formatExactTime(msg.timestamp);
143вҶ’  const hasItems = msg.items.length > 0;
144вҶ’  const hasPanels = panelStack.length > 0;
145вҶ’
146вҶ’  // Stack manipulation
147вҶ’  const openSubagentFromMain = useCallback((item: DisplayItem) => {
148вҶ’    if (bodyRef.current) {
149вҶ’      savedScroll.current = bodyRef.current.scrollTop;
150вҶ’    }
151вҶ’    setPanelStack((prev) => {
152вҶ’      if (
153вҶ’        prev.length === 1 &&
154вҶ’        prev[0].kind === "agent-list" &&
155вҶ’        prev[0].item.agent_id === item.agent_id
156вҶ’      ) {
157вҶ’        return [];
158вҶ’      }
159вҶ’      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
160вҶ’    });
161вҶ’    setColumnWidths((prev) => [prev[0]]);
162вҶ’    setFocusedColumn(1);
163вҶ’  }, []);
164вҶ’
165вҶ’  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
166вҶ’    setPanelStack((prev) => {
167вҶ’      const next = prev.slice(0, depth + 1);
168вҶ’      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
169вҶ’      return next;
170вҶ’    });
171вҶ’    setColumnWidths((prev) => prev.slice(0, depth + 2));
172вҶ’    setFocusedColumn(depth + 2);
173вҶ’  }, []);
174вҶ’
175вҶ’  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
176вҶ’    setPanelStack((prev) => {
177вҶ’      const entry = prev[depth];
178вҶ’      if (!entry || entry.kind !== "agent-list") return prev;
179вҶ’      const next = prev.slice(0, depth);
180вҶ’      next.push({
181вҶ’        kind: "agent-detail",
182вҶ’        item: entry.item,
183вҶ’        msg: detailMsg,
184вҶ’        key: entry.key + ":detail",
185вҶ’      });
186вҶ’      return next;
187вҶ’    });
188вҶ’  }, []);
189вҶ’
190вҶ’  const backToListAt = useCallback((depth: number) => {
191вҶ’    setPanelStack((prev) => {
192вҶ’      const entry = prev[depth];
193вҶ’      if (!entry || entry.kind !== "agent-detail") return prev;
194вҶ’      const next = prev.slice(0, depth);
195вҶ’      next.push({
196вҶ’        kind: "agent-list",
197вҶ’        item: entry.item,
198вҶ’        key: entry.item.agent_id || `panel-${depth}`,
199вҶ’      });
200вҶ’      return next;
201вҶ’    });
202вҶ’  }, []);
203вҶ’
204вҶ’  const closeAt = useCallback((depth: number) => {
205вҶ’    setPanelStack((prev) => prev.slice(0, depth));
206вҶ’    setColumnWidths((prev) => prev.slice(0, depth + 1));
207вҶ’    setFocusedColumn((prev) => Math.min(prev, depth));
208вҶ’  }, []);
209вҶ’
210вҶ’  const setColumnWidth = useCallback((colIndex: number, width: number) => {
211вҶ’    setColumnWidths((prev) => {
212вҶ’      const next = [...prev];
213вҶ’      while (next.length <= colIndex) next.push(null);
214вҶ’      next[colIndex] = width;
215вҶ’      return next;
216вҶ’    });
217вҶ’  }, []);
218вҶ’
219вҶ’  const handleItemClick = (index: number, item: DisplayItem) => {
220вҶ’    setSelectedItem(index);
221вҶ’    setFocusedColumn(0);
222вҶ’    if (item.subagent_messages.length > 0) {
223вҶ’      openSubagentFromMain(item);
224вҶ’    } else {
225вҶ’      toggleItem(index);
226вҶ’    }
227вҶ’  };
228вҶ’
229вҶ’  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
230вҶ’    if (nav) {
231вҶ’      panelRefs.current.set(depth, nav);
232вҶ’    } else {
233вҶ’      panelRefs.current.delete(depth);
234вҶ’    }
235вҶ’  }, []);
236вҶ’
237вҶ’  // Single keyboard handler for all columns
238вҶ’  const detailKeyMap: Record<string, () => void> = {};
239вҶ’
240вҶ’  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
241вҶ’  const moveDown = () => {
242вҶ’    if (focusedColumn === 0) {
243вҶ’      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
244вҶ’    } else {
245вҶ’      const nav = panelRefs.current.get(focusedColumn - 1);
246вҶ’      nav?.moveDown();
247вҶ’    }
248вҶ’  };
249вҶ’  const moveUp = () => {
250вҶ’    if (focusedColumn === 0) {
251вҶ’      setSelectedItem((i) => Math.max(i - 1, 0));
252вҶ’    } else {
253вҶ’      const nav = panelRefs.current.get(focusedColumn - 1);
254вҶ’      nav?.moveUp();
255вҶ’    }
256вҶ’  };
257вҶ’  detailKeyMap["j"] = moveDown;
258вҶ’  detailKeyMap["ArrowDown"] = moveDown;
259вҶ’  detailKeyMap["k"] = moveUp;
260вҶ’  detailKeyMap["ArrowUp"] = moveUp;
261вҶ’  detailKeyMap["Tab"] = () => {
262вҶ’    if (focusedColumn === 0) {
263вҶ’      const item = msg.items[selectedItem];
264вҶ’      if (item) handleItemClick(selectedItem, item);
265вҶ’    } else {
266вҶ’      const nav = panelRefs.current.get(focusedColumn - 1);
267вҶ’      nav?.toggle();
268вҶ’    }
269вҶ’  };
270вҶ’  detailKeyMap["Enter"] = () => {
271вҶ’    if (focusedColumn === 0) {
272вҶ’      const item = msg.items[selectedItem];
273вҶ’      if (item && item.subagent_messages.length > 0) {
274вҶ’        openSubagentFromMain(item);
275вҶ’      } else if (item) {
276вҶ’        toggleItem(selectedItem);
277вҶ’      }
278вҶ’    } else {
279вҶ’      const nav = panelRefs.current.get(focusedColumn - 1);
280вҶ’      nav?.enter();
281вҶ’    }
282вҶ’  };
283вҶ’
284вҶ’  // h/l or ArrowLeft/ArrowRight to switch focused column
285вҶ’  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
286вҶ’  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
287вҶ’  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
288вҶ’  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
289вҶ’
290вҶ’  // q = go back to list
291вҶ’  detailKeyMap["q"] = onBack;
292вҶ’  // Escape = close rightmost panel, or go back
293вҶ’  detailKeyMap["Escape"] = () => {
294вҶ’    if (panelStack.length > 0) {
295вҶ’      closeAt(panelStack.length - 1);
296вҶ’    } else {
297вҶ’      onBack();
298вҶ’    }
299вҶ’  };
300вҶ’
301вҶ’  useKeyboard(detailKeyMap);
302вҶ’
303вҶ’  const mainWidthStyle =
304вҶ’    hasPanels && columnWidths[0]
305вҶ’      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
306вҶ’      : undefined;
307вҶ’
308вҶ’  return (
309вҶ’    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
310вҶ’      <div
311вҶ’        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
312вҶ’        style={mainWidthStyle}
313вҶ’        onClick={() => setFocusedColumn(0)}
314вҶ’      >
315вҶ’        <div className="message-detail__header">
316вҶ’          <BackButton onClick={onBack} />
317вҶ’          <span className="message-detail__title">
318вҶ’            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
319вҶ’          </span>
320вҶ’          {model && (
321вҶ’            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
322вҶ’          )}
323вҶ’          {msg.subagent_label && (
324вҶ’            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
325вҶ’          )}
326вҶ’          <span className="message-detail__meta">
327вҶ’            {time}
328вҶ’            {msg.tokens_raw > 0 && (
329вҶ’              <>
330вҶ’                {" "}
331вҶ’                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
332вҶ’              </>
333вҶ’            )}
334вҶ’            {msg.duration_ms > 0 && (
335вҶ’              <>
336вҶ’                {" "}
337вҶ’                {"\u00B7"} {formatDuration(msg.duration_ms)}
338вҶ’              </>
339вҶ’            )}
340вҶ’          </span>
341вҶ’        </div>
342вҶ’
343вҶ’        <div className="message-detail__body" ref={bodyRef}>
344вҶ’          <div className="message-detail__content">
345вҶ’            {msg.content && (
346вҶ’              <div className="message-detail__text">
347вҶ’                <ReactMarkdown>{msg.content}</ReactMarkdown>
348вҶ’              </div>
349вҶ’            )}
350вҶ’            {hasItems && (
351вҶ’              <div className="detail-items">
352вҶ’                <div className="detail-items__section-label">Items ({msg.items.length})</div>
353вҶ’                {msg.items.map((item, idx) => (
354вҶ’                  <DetailItem
355вҶ’                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
356вҶ’                    ref={idx === selectedItem ? scrollRef : undefined}
357вҶ’                    item={item}
358вҶ’                    index={idx}
359вҶ’                    isSelected={idx === selectedItem}
360вҶ’                    isExpanded={expandedItems.has(idx)}
361вҶ’                    isAgentActive={
362вҶ’                      panelStack.length > 0 &&
363вҶ’                      panelStack[0].item.agent_id === item.agent_id &&
364вҶ’                      !!item.agent_id
365вҶ’                    }
366вҶ’                    onToggle={handleItemClick}
367вҶ’                    onToggleExpand={toggleItem}
368вҶ’                    onSelect={setSelectedItem}
369вҶ’                  />
370вҶ’                ))}
371вҶ’              </div>
372вҶ’            )}
373вҶ’            {ongoing && (
374вҶ’              <div className="message-detail__ongoing">
375вҶ’                <OngoingDots />
376вҶ’              </div>
377вҶ’            )}
378вҶ’          </div>
379вҶ’        </div>
380вҶ’      </div>
381вҶ’
382вҶ’      {panelStack.map((entry, depth) => {
383вҶ’        const colWidth = columnWidths[depth + 1];
384вҶ’        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
385вҶ’        const isFocused = focusedColumn === depth + 1;
386вҶ’
387вҶ’        return (
388вҶ’          <PanelColumn
389вҶ’            key={entry.key}
390вҶ’            entry={entry}
391вҶ’            depth={depth}
392вҶ’            style={widthStyle}
393вҶ’            isFocused={isFocused}
394вҶ’            panelStack={panelStack}
395вҶ’            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
396вҶ’            onBackToList={() => backToListAt(depth)}
397вҶ’            onOpenSubagent={(item) => openSubagentAt(depth, item)}
398вҶ’            onClose={() => closeAt(depth)}
399вҶ’            onResize={(w) => setColumnWidth(depth, w)}
400вҶ’            onFocus={() => setFocusedColumn(depth + 1)}
401вҶ’            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
402вҶ’          />
403вҶ’        );
404вҶ’      })}
405вҶ’    </div>
406вҶ’  );
407вҶ’}
408вҶ’
409вҶ’/* в”Җв”Җв”Җ PanelColumn: renders ResizeHandle + either list or detail в”Җв”Җв”Җ */
410вҶ’
411вҶ’interface PanelColumnProps {
412вҶ’  entry: PanelEntry;
413вҶ’  depth: number;
414вҶ’  style?: React.CSSProperties;
415вҶ’  isFocused: boolean;
416вҶ’  panelStack: PanelEntry[];
417вҶ’  onOpenDetail: (msg: DisplayMessage) => void;
418вҶ’  onBackToList: () => void;
419вҶ’  onOpenSubagent: (item: DisplayItem) => void;
420вҶ’  onClose: () => void;
421вҶ’  onResize: (width: number) => void;
422вҶ’  onFocus: () => void;
423вҶ’  onRegisterNav: (nav: ColumnNav | null) => void;
424вҶ’}
425вҶ’
426вҶ’function PanelColumn({
427вҶ’  entry,
428вҶ’  depth,
429вҶ’  style,
430вҶ’  isFocused,
431вҶ’  panelStack,
432вҶ’  onOpenDetail,
433вҶ’  onBackToList,
434вҶ’  onOpenSubagent,
435вҶ’  onClose,
436вҶ’  onResize,
437вҶ’  onFocus,
438вҶ’  onRegisterNav,
439вҶ’}: PanelColumnProps) {
440вҶ’  return (
441вҶ’    <>
442вҶ’      <ResizeHandle onResize={onResize} />
443вҶ’      {entry.kind === "agent-list" ? (
444вҶ’        <AgentListColumn
445вҶ’          item={entry.item}
446вҶ’          style={style}
447вҶ’          isFocused={isFocused}
448вҶ’          onOpenDetail={onOpenDetail}
449вҶ’          onClose={onClose}
450вҶ’          onFocus={onFocus}
451вҶ’          onRegisterNav={onRegisterNav}
452вҶ’        />
453вҶ’      ) : (
454вҶ’        <AgentDetailColumn
455вҶ’          item={entry.item}
456вҶ’          msg={entry.msg}
457вҶ’          style={style}
458вҶ’          isFocused={isFocused}
459вҶ’          depth={depth}
460вҶ’          panelStack={panelStack}
461вҶ’          onOpenSubagent={onOpenSubagent}
462вҶ’          onBack={onBackToList}
463вҶ’          onClose={onClose}
464вҶ’          onFocus={onFocus}
465вҶ’          onRegisterNav={onRegisterNav}
466вҶ’        />
467вҶ’      )}
468вҶ’    </>
469вҶ’  );
470вҶ’}
471вҶ’
472вҶ’/* в”Җв”Җв”Җ AgentListColumn: shows agent header + message list в”Җв”Җв”Җ */
473вҶ’
474вҶ’interface AgentListColumnProps {
475вҶ’  item: DisplayItem;
476вҶ’  style?: React.CSSProperties;
477вҶ’  isFocused: boolean;
478вҶ’  onOpenDetail: (msg: DisplayMessage) => void;
479вҶ’  onClose: () => void;
480вҶ’  onFocus: () => void;
481вҶ’  onRegisterNav: (nav: ColumnNav | null) => void;
482вҶ’}
483вҶ’
484вҶ’function AgentListColumn({
485вҶ’  item,
486вҶ’  style,
487вҶ’  isFocused,
488вҶ’  onOpenDetail,
489вҶ’  onClose,
490вҶ’  onFocus,
491вҶ’  onRegisterNav,
492вҶ’}: AgentListColumnProps) {
493вҶ’  const messages = item.subagent_messages;
494вҶ’  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
495вҶ’  const {
496вҶ’    set: expandedSet,
497вҶ’    toggle: toggleMsg,
498вҶ’    addAll: expandAllMsgs,
499вҶ’    clear: clearMsgs,
500вҶ’  } = useToggleSet();
501вҶ’  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
502вҶ’  const selectedRef = useScrollToSelected(selectedMsg);
503вҶ’  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
504вҶ’
505вҶ’  const handleClick = useCallback(
506вҶ’    (index: number) => {
507вҶ’      onFocus();
508вҶ’      if (selectedMsg === index) {
509вҶ’        toggleMsg(index);
510вҶ’      } else {
511вҶ’        setSelectedMsg(index);
512вҶ’      }
513вҶ’    },
514вҶ’    [selectedMsg, toggleMsg, onFocus],
515вҶ’  );
516вҶ’
517вҶ’  // Expose navigation to parent via callback ref
518вҶ’  const navRef = useRef<ColumnNav>({
519вҶ’    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
520вҶ’    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
521вҶ’    toggle: () => toggleMsg(selectedMsg),
522вҶ’    enter: () => {
523вҶ’      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
524вҶ’    },
525вҶ’    itemCount: () => messages.length,
526вҶ’    expandAll: () => expandAllMsgs(messages.map((_, i) => i)),
527вҶ’    collapseAll: () => clearMsgs(),
528вҶ’  });
529вҶ’  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
530вҶ’  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
531вҶ’  navRef.current.toggle = () => toggleMsg(selectedMsg);
532вҶ’  navRef.current.enter = () => {
533вҶ’    if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
534вҶ’  };
