  1вҶ’/**
  2вҶ’ * Safe wrapper around Tauri's `invoke`.
  3вҶ’ *
  4вҶ’ * In the Tauri webview it delegates to the real IPC bridge.
  5вҶ’ * In a plain browser it calls the Rust backend's HTTP API.
  6вҶ’ */
  7вҶ’import { invoke as tauriInvoke } from "@tauri-apps/api/core";
  8вҶ’import { isTauri } from "./isTauri";
  9вҶ’import { API_BASE } from "./config";
 10вҶ’
 11вҶ’// ---------------------------------------------------------------------------
 12вҶ’// Route map вҖ” add new commands here without touching invoke logic (OCP).
 13вҶ’// ---------------------------------------------------------------------------
 14вҶ’
 15вҶ’interface Route {
 16вҶ’  method?: "POST";
 17вҶ’  path: string | ((args: Record<string, unknown>) => string);
 18вҶ’  body?: (args: Record<string, unknown>) => unknown;
 19вҶ’}
 20вҶ’
 21вҶ’/** Declarative mapping from Tauri command names to HTTP endpoints. */
 22вҶ’const routes: Record<string, Route> = {
 23вҶ’  get_settings: { path: "/api/settings" },
 24вҶ’  set_projects_dir: {
 25вҶ’    method: "POST",
 26вҶ’    path: "/api/settings/dir",
 27вҶ’    body: (a) => ({ path: a.path ?? null }),
 28вҶ’  },
 29вҶ’  get_project_dirs: { path: "/api/project-dirs" },
 30вҶ’  discover_sessions: {
 31вҶ’    path: (a) => {
 32вҶ’      const dirs = (a.projectDirs as string[]) ?? [];
 33вҶ’      return `/api/sessions?dirs=${encodeURIComponent(dirs.join(","))}`;
 34вҶ’    },
 35вҶ’  },
 36вҶ’  load_session: {
 37вҶ’    method: "POST",
 38вҶ’    path: "/api/session/load",
 39вҶ’    body: (a) => ({ path: a.path }),
 40вҶ’  },
 41вҶ’  get_session_meta: {
 42вҶ’    path: (a) => `/api/session/meta?path=${encodeURIComponent(String(a.path ?? ""))}`,
 43вҶ’  },
 44вҶ’  watch_session: {
 45вҶ’    method: "POST",
 46вҶ’    path: "/api/session/watch",
 47вҶ’    body: (a) => ({ path: a.path }),
 48вҶ’  },
 49вҶ’  unwatch_session: { method: "POST", path: "/api/session/unwatch" },
 50вҶ’  watch_picker: {
 51вҶ’    method: "POST",
 52вҶ’    path: "/api/picker/watch",
 53вҶ’    body: (a) => ({ projectDirs: a.projectDirs }),
 54вҶ’  },
 55вҶ’  unwatch_picker: { method: "POST", path: "/api/picker/unwatch" },
 56вҶ’  get_git_info: {
 57вҶ’    path: (a) => `/api/git-info?cwd=${encodeURIComponent(String(a.cwd ?? ""))}`,
 58вҶ’  },
 59вҶ’  get_debug_log: {
 60вҶ’    path: (a) => {
 61вҶ’      const params = new URLSearchParams();
 62вҶ’      params.set("path", String(a.sessionPath ?? ""));
 63вҶ’      if (a.minLevel) params.set("minLevel", String(a.minLevel));
 64вҶ’      if (a.filterText) params.set("filterText", String(a.filterText));
 65вҶ’      return `/api/debug-log?${params}`;
 66вҶ’    },
 67вҶ’  },
 68вҶ’};
 69вҶ’
 70вҶ’// ---------------------------------------------------------------------------
 71вҶ’// HTTP transport (SRP вҖ” only handles fetch, not routing).
 72вҶ’// ---------------------------------------------------------------------------
 73вҶ’
 74вҶ’async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
 75вҶ’  const res = await fetch(url, {
 76вҶ’    ...init,
 77вҶ’    headers: { "Content-Type": "application/json", ...init?.headers },
 78вҶ’  });
 79вҶ’  if (!res.ok) {
 80вҶ’    const body = await res.json().catch(() => ({ error: res.statusText }));
 81вҶ’    throw new Error(body.error ?? res.statusText);
 82вҶ’  }
 83вҶ’  const text = await res.text();
 84вҶ’  return text ? (JSON.parse(text) as T) : (undefined as T);
 85вҶ’}
 86вҶ’
 87вҶ’/** Resolve a route to a fetch call. */
 88вҶ’async function httpInvoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
 89вҶ’  const route = routes[cmd];
 90вҶ’  if (!route) {
 91вҶ’    throw new Error(`[web] Unknown command "${cmd}"`);
 92вҶ’  }
 93вҶ’  const a = args ?? {};
 94вҶ’  const path = typeof route.path === "function" ? route.path(a) : route.path;
 95вҶ’  const init: RequestInit = {};
 96вҶ’  if (route.method) init.method = route.method;
 97вҶ’  if (route.body) init.body = JSON.stringify(route.body(a));
 98вҶ’  return fetchJson<T>(`${API_BASE}${path}`, init);
 99вҶ’}
100вҶ’
101вҶ’// ---------------------------------------------------------------------------
102вҶ’// Public API
103вҶ’// ---------------------------------------------------------------------------
104вҶ’
105вҶ’/**
106вҶ’ * Drop-in replacement for `import { invoke } from "@tauri-apps/api/core"`.
107вҶ’ * Works in both Tauri and plain-browser environments.
108вҶ’ */
109вҶ’export async function invoke<T>(cmd: string, args?: Record<string, unknown>): Promise<T> {
110вҶ’  if (isTauri) {
111вҶ’    return tauriInvoke<T>(cmd, args);
112вҶ’  }
113вҶ’  return httpInvoke<T>(cmd, args);
114вҶ’}
