 25вҶ’];
 26вҶ’
 27вҶ’const listKeysWithTeams: KeyHint[] = [
 28вҶ’  ...listKeys.slice(0, 6),
 29вҶ’  { key: "t", label: "tasks" },
 30вҶ’  ...listKeys.slice(6),
 31вҶ’];
 32вҶ’
 33вҶ’const detailKeys: KeyHint[] = [
 34вҶ’  { key: "j/k", label: "items" },
 35вҶ’  { key: "Tab", label: "toggle" },
 36вҶ’  { key: "Enter", label: "open" },
 37вҶ’  { key: "h/l", label: "panels" },
 38вҶ’  { key: "q/Esc", label: "back" },
 39вҶ’];
 40вҶ’
 41вҶ’const pickerKeys: KeyHint[] = [
 42вҶ’  { key: "j/k", label: "nav" },
 43вҶ’  { key: "Enter", label: "open" },
 44вҶ’  { key: "/", label: "search" },
 45вҶ’  { key: "q/Esc", label: "back" },
 46вҶ’];
 47вҶ’
 48вҶ’const debugKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
 49вҶ’
 50вҶ’const teamKeys: KeyHint[] = [{ key: "q/Esc", label: "back" }];
 51вҶ’
 52вҶ’function getKeys(view: ViewState, hasTeams: boolean): KeyHint[] {
 53вҶ’  switch (view) {
 54вҶ’    case "list":
 55вҶ’      return hasTeams ? listKeysWithTeams : listKeys;
 56вҶ’    case "detail":
 57вҶ’      return detailKeys;
 58вҶ’    case "picker":
 59вҶ’      return pickerKeys;
 60вҶ’    case "debug":
 61вҶ’      return debugKeys;
 62вҶ’    case "team":
