 67вҶ’export function KeybindBar({
 68вҶ’  view,
 69вҶ’  hasTeams,
 70вҶ’  showHints = true,
 71вҶ’  onToggle,
 72вҶ’  actions,
 73вҶ’}: KeybindBarProps) {
 74вҶ’  const keys = getKeys(view, hasTeams);
 75вҶ’
 76вҶ’  return (
 77вҶ’    <div className="keybind-bar">
 78вҶ’      {showHints &&
 79вҶ’        keys.map((hint) => {
 80вҶ’          const action = actions?.[hint.label];
 81вҶ’          return (
 82вҶ’            <span
 83вҶ’              key={hint.key}
 84вҶ’              className={`keybind-bar__item${action ? " keybind-bar__item--clickable" : ""}`}
 85вҶ’              onClick={action}
 86вҶ’            >
 87вҶ’              <span className="keybind-bar__key">{hint.key}</span>
 88вҶ’              <span className="keybind-bar__label">{hint.label}</span>
 89вҶ’            </span>
 90вҶ’          );
 91вҶ’        })}
 92вҶ’      {onToggle && (
 93вҶ’        <button
 94вҶ’          className="keybind-bar__toggle"
 95вҶ’          onClick={onToggle}
 96вҶ’          title={showHints ? "Hide keybinds" : "Show keybinds"}
 97вҶ’        >
 98вҶ’          ?
 99вҶ’        </button>
100вҶ’      )}
101вҶ’    </div>
102вҶ’  );
103вҶ’}
