 1вҶ’import { useEffect, useRef } from "react";
 2вҶ’import { EventSource } from "eventsource";
 3вҶ’
 4вҶ’const API = "http://127.0.0.1:11423";
 5вҶ’
 6вҶ’/** Subscribe to SSE events from the Rust backend. */
 7вҶ’export function useSSE<T>(event: string, handler: (payload: T) => void) {
 8вҶ’  const handlerRef = useRef(handler);
 9вҶ’  handlerRef.current = handler;
10вҶ’
11вҶ’  useEffect(() => {
12вҶ’    const source = new EventSource(`${API}/api/events`);
13вҶ’    const onMessage = (e: MessageEvent) => {
14вҶ’      try {
15вҶ’        handlerRef.current(JSON.parse(e.data) as T);
16вҶ’      } catch {
17вҶ’        // ignore malformed events
18вҶ’      }
19вҶ’    };
20вҶ’    source.addEventListener(event, onMessage as EventListener);
21вҶ’    return () => {
22вҶ’      source.removeEventListener(event, onMessage as EventListener);
23вҶ’      source.close();
24вҶ’    };
25вҶ’  }, [event]);
26вҶ’}
27вҶ’

  1вҶ’// Format utilities вҖ” ported from format.go
  2вҶ’// Pure shared utilities are re-exported from shared/format.ts.
  3вҶ’
  4вҶ’import type { DisplayMessage } from "../types";
  5вҶ’export { formatTokens } from "../../shared/format";
  6вҶ’
  7вҶ’/**
  8вҶ’ * Turns "claude-opus-4-6" into "opus4.6".
  9вҶ’ */
 10вҶ’export function shortModel(m: string): string {
 11вҶ’  m = m.replace(/^claude-/, "");
 12вҶ’  const dashIdx = m.indexOf("-");
 13вҶ’  if (dashIdx === -1) return m;
 14вҶ’
 15вҶ’  const family = m.slice(0, dashIdx);
 16вҶ’  const rest = m.slice(dashIdx + 1);
 17вҶ’  // Keep major-minor only, drop patch/build metadata
 18вҶ’  const vParts = rest.split("-");
 19вҶ’  let version = vParts[0];
 20вҶ’  if (vParts.length >= 2) {
 21вҶ’    version = vParts[0] + "." + vParts[1];
 22вҶ’  }
 23вҶ’  return family + version;
 24вҶ’}
 25вҶ’
 26вҶ’// Claude API pricing per million tokens (USD).
 27вҶ’// Model-specific rates; we pick by the model string prefix.
 28вҶ’const MODEL_PRICING: {
 29вҶ’  prefix: string;
 30вҶ’  input: number;
 31вҶ’  output: number;
 32вҶ’  cacheRead: number;
 33вҶ’  cacheWrite: number;
 34вҶ’}[] = [
 35вҶ’  { prefix: "opus", input: 5, output: 25, cacheRead: 0.5, cacheWrite: 6.25 },
 36вҶ’  { prefix: "sonnet", input: 3, output: 15, cacheRead: 0.3, cacheWrite: 3.75 },
 37вҶ’  { prefix: "haiku", input: 1, output: 5, cacheRead: 0.1, cacheWrite: 1.25 },
 38вҶ’];
 39вҶ’
 40вҶ’function pricingForModel(model: string) {
 41вҶ’  const m = model.toLowerCase();
 42вҶ’  return MODEL_PRICING.find((p) => m.includes(p.prefix)) ?? MODEL_PRICING[1]; // default sonnet
 43вҶ’}
 44вҶ’
 45вҶ’/**
 46вҶ’ * Estimates USD cost from token breakdown and model string.
 47вҶ’ */
 48вҶ’export function estimateCost(
 49вҶ’  input: number,
 50вҶ’  output: number,
 51вҶ’  cacheRead: number,
 52вҶ’  cacheWrite: number,
 53вҶ’  model: string,
 54вҶ’): number {
 55вҶ’  const p = pricingForModel(model);
 56вҶ’  return (
 57вҶ’    (input * p.input + output * p.output + cacheRead * p.cacheRead + cacheWrite * p.cacheWrite) /
 58вҶ’    1_000_000
 59вҶ’  );
 60вҶ’}
 61вҶ’
 62вҶ’/**
 63вҶ’ * Formats a dollar amount: 0.0023 -> "0.00", 1.23 -> "1.23", 12.5 -> "12.50"
 64вҶ’ */
 65вҶ’export function formatCost(usd: number): string {
 66вҶ’  return usd.toFixed(2);
 67вҶ’}
 68вҶ’
 69вҶ’/**
 70вҶ’ * Formats milliseconds into human-readable duration.
 71вҶ’ */
 72вҶ’export function formatDuration(ms: number): string {
 73вҶ’  const secs = ms / 1000;
 74вҶ’  if (secs >= 60) {
 75вҶ’    const mins = Math.floor(secs / 60);
 76вҶ’    const rem = Math.floor(secs % 60);
 77вҶ’    return `${mins}m ${rem}s`;
 78вҶ’  }
 79вҶ’  if (secs >= 10) return `${Math.round(secs)}s`;
 80вҶ’  return `${secs.toFixed(1)}s`;
 81вҶ’}
 82вҶ’
 83вҶ’/**
 84вҶ’ * Returns the project display name from a cwd path.
 85вҶ’ * Extracts the last path segment.
 86вҶ’ */
 87вҶ’export function shortPath(cwd: string, _gitBranch?: string): string {
 88вҶ’  if (!cwd) return "";
 89вҶ’  const parts = cwd.split("/").filter(Boolean);
 90вҶ’  return parts[parts.length - 1] ?? cwd;
 91вҶ’}
 92вҶ’
 93вҶ’/**
 94вҶ’ * Returns a human-readable label for a permission mode.
 95вҶ’ */
 96вҶ’export function shortMode(mode: string): string {
 97вҶ’  switch (mode) {
 98вҶ’    case "default":
 99вҶ’      return "default";
100вҶ’    case "acceptEdits":
101вҶ’      return "auto-edit";
102вҶ’    case "bypassPermissions":
103вҶ’      return "yolo";
104вҶ’    case "plan":
105вҶ’      return "plan";
106вҶ’    default:
107вҶ’      return mode;
108вҶ’  }
109вҶ’}
110вҶ’
111вҶ’/**
112вҶ’ * Returns context window usage percentage (0-100).
113вҶ’ * Returns -1 if no usage data is available.
114вҶ’ */
115вҶ’export function contextPercent(msgs: DisplayMessage[]): number {
116вҶ’  const contextWindowSize = 1_000_000;
117вҶ’  for (let i = msgs.length - 1; i >= 0; i--) {
118вҶ’    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
119вҶ’      const pct = Math.floor((msgs[i].context_tokens * 100) / contextWindowSize);
120вҶ’      return Math.min(pct, 100);
121вҶ’    }
122вҶ’  }
123вҶ’  return -1;
124вҶ’}
125вҶ’
126вҶ’/**
127вҶ’ * Formats a timestamp as yyyy-mm-dd hh:mm:ss.
128вҶ’ */
129вҶ’export function formatExactTime(ts: string): string {
130вҶ’  if (!ts) return "";
131вҶ’  try {
132вҶ’    const d = new Date(ts);
133вҶ’    if (isNaN(d.getTime())) return "";
134вҶ’    const yyyy = d.getFullYear();
135вҶ’    const mm = String(d.getMonth() + 1).padStart(2, "0");
136вҶ’    const dd = String(d.getDate()).padStart(2, "0");
137вҶ’    const hh = String(d.getHours()).padStart(2, "0");
138вҶ’    const mi = String(d.getMinutes()).padStart(2, "0");
139вҶ’    const ss = String(d.getSeconds()).padStart(2, "0");
140вҶ’    return `${yyyy}-${mm}-${dd} ${hh}:${mi}:${ss}`;
141вҶ’  } catch {
142вҶ’    return "";
143вҶ’  }
144вҶ’}
145вҶ’
146вҶ’/**
147вҶ’ * Groups sessions by date category, sorted by mod_time descending within each group.
148вҶ’ */
149вҶ’export function groupByDate<T extends { mod_time: string }>(
150вҶ’  items: T[],
151вҶ’): { category: string; items: T[] }[] {
152вҶ’  const now = new Date();
153вҶ’  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
154вҶ’  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
155вҶ’  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
156вҶ’  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);
157вҶ’
158вҶ’  const groups: Record<string, T[]> = {};
159вҶ’  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];
160вҶ’
161вҶ’  for (const item of items) {
162вҶ’    const d = new Date(item.mod_time);
163вҶ’    let cat: string;
164вҶ’    if (d >= todayStart) cat = "Today";
165вҶ’    else if (d >= yesterdayStart) cat = "Yesterday";
166вҶ’    else if (d >= weekStart) cat = "This Week";
167вҶ’    else if (d >= monthStart) cat = "This Month";
168вҶ’    else cat = "Older";
169вҶ’
170вҶ’    (groups[cat] ??= []).push(item);
171вҶ’  }
172вҶ’
173вҶ’  // Sort each group by mod_time descending (most recent first)
174вҶ’  for (const cat of order) {
175вҶ’    if (groups[cat]) {
176вҶ’      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
177вҶ’    }
178вҶ’  }
179вҶ’
180вҶ’  return order
181вҶ’    .filter((cat) => groups[cat]?.length)
182вҶ’    .map((category) => ({ category, items: groups[category] }));
183вҶ’}
184вҶ’
185вҶ’/**
186вҶ’ * Truncates text to maxLen, appending ellipsis if needed.
187вҶ’ */
188вҶ’export function truncate(text: string, maxLen: number): string {
189вҶ’  if (text.length <= maxLen) return text;
190вҶ’  return text.slice(0, maxLen - 1) + "\u2026";
191вҶ’}
192вҶ’
193вҶ’/**
194вҶ’ * Returns the first non-empty line of text.
195вҶ’ */
196вҶ’export function firstLine(text: string): string {
197вҶ’  const idx = text.indexOf("\n");
198вҶ’  return idx === -1 ? text : text.slice(0, idx);
199вҶ’}
200вҶ’
201вҶ’/**
202вҶ’ * Pretty-prints a JSON string. Returns the original string on parse failure.
203вҶ’ */
204вҶ’export function formatJson(input: string): string {
205вҶ’  try {
206вҶ’    return JSON.stringify(JSON.parse(input), null, 2);
207вҶ’  } catch {
208вҶ’    return input;
209вҶ’  }
210вҶ’}
211вҶ’
212вҶ’/**
213вҶ’ * Extract the encoded project directory key from a session path.
214вҶ’ */
215вҶ’export function projectKey(path: string): string {
216вҶ’  const match = path.match(/[/\\]\.claude[/\\]projects[/\\]([^/\\]+)/);
217вҶ’  return match ? match[1] : "unknown";
218вҶ’}
219вҶ’
220вҶ’/**
221вҶ’ * Decode a Claude projects directory key (e.g. "-Users-yang-liu-Envato-others-my-project")
222вҶ’ * back to a path and return the last segment via shortPath.
223вҶ’ */
224вҶ’export function projectDisplayName(key: string): string {
225вҶ’  const path = key.replace(/^-/, "/").replaceAll("-", "/");
226вҶ’  return shortPath(path) || key;
227вҶ’}
