 1вҶ’/**
 2вҶ’ * Safe wrapper around Tauri's `listen`.
 3вҶ’ *
 4вҶ’ * In the Tauri webview it delegates to the real event system.
 5вҶ’ * In a plain browser it subscribes to the Rust backend's SSE endpoint.
 6вҶ’ */
 7вҶ’import { listen as tauriListen } from "@tauri-apps/api/event";
 8вҶ’import { isTauri } from "./isTauri";
 9вҶ’import { API_BASE } from "./config";
10вҶ’
11вҶ’export type UnlistenFn = () => void;
12вҶ’
13вҶ’/** Shared SSE connection вҖ” lazily created, ref-counted. */
14вҶ’let sseSource: EventSource | null = null;
15вҶ’let sseRefCount = 0;
16вҶ’
17вҶ’function ensureSse(): EventSource {
18вҶ’  if (!sseSource || sseSource.readyState === EventSource.CLOSED) {
19вҶ’    sseSource = new EventSource(`${API_BASE}/api/events`);
20вҶ’  }
21вҶ’  sseRefCount++;
22вҶ’  return sseSource;
23вҶ’}
24вҶ’
25вҶ’function releaseSse(): void {
26вҶ’  sseRefCount--;
27вҶ’  if (sseRefCount <= 0 && sseSource) {
28вҶ’    sseSource.close();
29вҶ’    sseSource = null;
30вҶ’    sseRefCount = 0;
31вҶ’  }
32вҶ’}
33вҶ’
34вҶ’export async function listen<T>(
35вҶ’  event: string,
36вҶ’  handler: (event: { payload: T }) => void,
37вҶ’): Promise<UnlistenFn> {
38вҶ’  if (isTauri) {
39вҶ’    return tauriListen<T>(event, handler);
40вҶ’  }
41вҶ’
42вҶ’  const source = ensureSse();
43вҶ’  const onMessage = (e: MessageEvent) => {
44вҶ’    try {
45вҶ’      const payload = JSON.parse(e.data) as T;
46вҶ’      handler({ payload });
47вҶ’    } catch {
48вҶ’      // ignore malformed events
49вҶ’    }
50вҶ’  };
51вҶ’  source.addEventListener(event, onMessage as EventListener);
52вҶ’
53вҶ’  return () => {
54вҶ’    source.removeEventListener(event, onMessage as EventListener);
55вҶ’    releaseSse();
56вҶ’  };
57вҶ’}
