 24вҶ’export function statsFromMessage(msg: DisplayMessage): Stats {
 25вҶ’  const agentCount = msg.items.filter(
 26вҶ’    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 27вҶ’  ).length;
 28вҶ’  return {
 29вҶ’    tokens: msg.tokens_raw,
 30вҶ’    toolCount: msg.tool_call_count,
 31вҶ’    thinkingCount: msg.thinking_count,
 32вҶ’    outputCount: msg.output_count,
 33вҶ’    durationMs: msg.duration_ms,
 34вҶ’    agentCount,
 35вҶ’    spawnCount: msg.teammate_spawns,
 36вҶ’  };
 37вҶ’}
 38вҶ’
 39вҶ’export function statsFromSubagentMessages(messages: DisplayMessage[]): Stats {
 40вҶ’  let tokens = 0;
 41вҶ’  let toolCount = 0;
 42вҶ’  let thinkingCount = 0;
 43вҶ’  let outputCount = 0;
 44вҶ’  let agentCount = 0;
 45вҶ’  for (const m of messages) {
 46вҶ’    tokens += m.tokens_raw;
 47вҶ’    toolCount += m.tool_call_count;
 48вҶ’    thinkingCount += m.thinking_count;
 49вҶ’    outputCount += m.output_count;
 50вҶ’    agentCount += m.items.filter(
 51вҶ’      (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
 52вҶ’    ).length;
 53вҶ’  }
 54вҶ’  return {
 55вҶ’    tokens,
 56вҶ’    toolCount,
 57вҶ’    thinkingCount,
 58вҶ’    outputCount,
 59вҶ’    durationMs: 0,
 60вҶ’    agentCount,
 61вҶ’    spawnCount: 0,
 62вҶ’  };
 63вҶ’}
 64вҶ’
 65вҶ’export function useSubagentStats(item: DisplayItem): Stats | null {
 66вҶ’  return useMemo(() => {
 67вҶ’    if (item.subagent_messages.length === 0) return null;
 68вҶ’    return statsFromSubagentMessages(item.subagent_messages);
 69вҶ’  }, [item.subagent_messages]);
 70вҶ’}
 71вҶ’
 72вҶ’function hasAny(s: Stats): boolean {
 73вҶ’  return (
 74вҶ’    s.tokens > 0 ||
 75вҶ’    s.toolCount > 0 ||
 76вҶ’    s.thinkingCount > 0 ||
 77вҶ’    s.outputCount > 0 ||
 78вҶ’    s.durationMs > 0 ||
 79вҶ’    s.agentCount > 0 ||
 80вҶ’    s.spawnCount > 0
 81вҶ’  );
 82вҶ’}
