 31вҶ’/// Start the HTTP API server on port 11423.
 32вҶ’pub async fn start_http_server(app: AppHandle) {
 33вҶ’    let state = Arc::new(HttpState { app });
 34вҶ’
 35вҶ’    let router = Router::new()
 36вҶ’        .route("/api/settings", get(api_get_settings))
 37вҶ’        .route("/api/settings/dir", post(api_set_projects_dir))
 38вҶ’        .route("/api/project-dirs", get(api_get_project_dirs))
 39вҶ’        .route("/api/sessions", get(api_discover_sessions))
 40вҶ’        .route("/api/session/load", post(api_load_session))
 41вҶ’        .route("/api/session/meta", get(api_get_session_meta))
 42вҶ’        .route("/api/session/watch", post(api_watch_session))
 43вҶ’        .route("/api/session/unwatch", post(api_unwatch_session))
 44вҶ’        .route("/api/picker/watch", post(api_watch_picker))
 45вҶ’        .route("/api/picker/unwatch", post(api_unwatch_picker))
 46вҶ’        .route("/api/git-info", get(api_get_git_info))
 47вҶ’        .route("/api/debug-log", get(api_get_debug_log))
 48вҶ’        .route("/api/events", get(api_events))
 49вҶ’        .layer(CorsLayer::permissive())
 50вҶ’        .with_state(state);
 51вҶ’
 52вҶ’    let listener = match tokio::net::TcpListener::bind("127.0.0.1:11423").await {
 53вҶ’        Ok(l) => l,
 54вҶ’        Err(e) => {
 55вҶ’            eprintln!("HTTP API: failed to bind port 11423: {e}");
 56вҶ’            return;
 57вҶ’        }
 58вҶ’    };
 59вҶ’    eprintln!("HTTP API: listening on http://127.0.0.1:11423");
 60вҶ’
 61вҶ’    if let Err(e) = axum::serve(listener, router).await {
 62вҶ’        eprintln!("HTTP API: server error: {e}");
 63вҶ’    }
 64вҶ’}
