  1вҶ’import { useState, useEffect, useCallback, useRef } from "react";
  2вҶ’import { invoke } from "./lib/invoke";
  3вҶ’import type { ViewState, SessionInfo } from "./types";
  4вҶ’import { useSession } from "./hooks/useSession";
  5вҶ’import { usePicker } from "./hooks/usePicker";
  6вҶ’import { useToggleSet } from "./hooks/useToggleSet";
  7вҶ’import { useKeyboard } from "./hooks/useKeyboard";
  8вҶ’import { useViewActionsRef, useViewActionCallbacks } from "./hooks/useViewActions";
  9вҶ’import { SessionPicker } from "./components/SessionPicker";
 10вҶ’import { MessageList } from "./components/MessageList";
 11вҶ’import { MessageDetail } from "./components/MessageDetail";
 12вҶ’import { TeamBoard } from "./components/TeamBoard";
 13вҶ’import { DebugViewer } from "./components/DebugViewer";
 14вҶ’import { InfoBar } from "./components/InfoBar";
 15вҶ’import { KeybindBar } from "./components/KeybindBar";
 16вҶ’import { ViewToolbar } from "./components/ViewToolbar";
 17вҶ’import { ProjectTree, useProjectKeys } from "./components/ProjectTree";
 18вҶ’import { ResizeHandle } from "./components/ResizeHandle";
 19вҶ’import { SettingsModal } from "./components/SettingsModal";
 20вҶ’
 21вҶ’export function App() {
 22вҶ’  const [view, setView] = useState<ViewState>("picker");
 23вҶ’  const [selectedMessage, setSelectedMessage] = useState(0);
 24вҶ’  const [pickerSelectedIndex, setPickerSelectedIndex] = useState(0);
 25вҶ’  const [showKeybinds, setShowKeybinds] = useState(true);
 26вҶ’  const [selectedProject, setSelectedProject] = useState<string | null>(null);
 27вҶ’  const [sidebarWidth, setSidebarWidth] = useState(180);
 28вҶ’  const [sidebarFocused, setSidebarFocused] = useState(false);
 29вҶ’  const [sidebarHighlight, setSidebarHighlight] = useState(0); // index in project list (0 = "All")
 30вҶ’  const [showSettings, setShowSettings] = useState(false);
 31вҶ’
 32вҶ’  const handleSelectProject = useCallback(
 33вҶ’    (project: string | null) => {
 34вҶ’      setSelectedProject(project);
 35вҶ’      setPickerSelectedIndex(0);
 36вҶ’      setSidebarFocused(false);
 37вҶ’      if (view !== "picker") setView("picker");
 38вҶ’    },
 39вҶ’    [view],
 40вҶ’  );
 41вҶ’
 42вҶ’  const session = useSession();
 43вҶ’  const picker = usePicker(selectedProject);
 44вҶ’  const projectKeys = useProjectKeys(picker.allSessions);
 45вҶ’
 46вҶ’  const { loadSession, loadDebugLog, sessionPath } = session;
 47вҶ’  const { discoverSessions, updateSessionOngoing } = picker;
 48вҶ’
 49вҶ’  const {
 50вҶ’    set: expandedMessages,
 51вҶ’    toggle: toggleMessage,
 52вҶ’    clear: clearExpanded,
 53вҶ’    addAll: expandMessages,
 54вҶ’  } = useToggleSet();
 55вҶ’
 56вҶ’  // Shared: fetch project dirs and discover sessions
 57вҶ’  const loadProjectDirs = useCallback(async () => {
 58вҶ’    try {
 59вҶ’      const dirs = await invoke<string[]>("get_project_dirs");
 60вҶ’      if (dirs.length > 0) {
 61вҶ’        discoverSessions(dirs);
 62вҶ’      }
 63вҶ’    } catch (err) {
 64вҶ’      console.error("Failed to get project dirs:", err);
 65вҶ’    }
 66вҶ’  }, [discoverSessions]);
 67вҶ’
 68вҶ’  // Auto-discover sessions on mount; show settings if no path configured
 69вҶ’  const discoveredRef = useRef(false);
 70вҶ’  useEffect(() => {
 71вҶ’    if (discoveredRef.current) return;
 72вҶ’    discoveredRef.current = true;
 73вҶ’    const discover = async () => {
 74вҶ’      let hasConfig = false;
 75вҶ’      try {
 76вҶ’        const settings = await invoke<{ projects_dir: string | null }>("get_settings");
 77вҶ’        hasConfig = settings.projects_dir != null;
 78вҶ’      } catch {
 79вҶ’        // no settings file yet
 80вҶ’      }
 81вҶ’      if (!hasConfig) {
 82вҶ’        setShowSettings(true);
 83вҶ’        return;
 84вҶ’      }
 85вҶ’      loadProjectDirs();
 86вҶ’    };
 87вҶ’    discover();
 88вҶ’  }, [loadProjectDirs]);
 89вҶ’
 90вҶ’  // Sync session watcher's ongoing status to picker (avoids race condition
 91вҶ’  // where picker watcher emits before session watcher updates).
 92вҶ’  useEffect(() => {
 93вҶ’    if (session.sessionPath) {
 94вҶ’      updateSessionOngoing(session.sessionPath, session.ongoing);
 95вҶ’    }
 96вҶ’  }, [session.sessionPath, session.ongoing, updateSessionOngoing]);
 97вҶ’
 98вҶ’  // Handle session selection from picker
 99вҶ’  const handleSelectSession = useCallback(
100вҶ’    (sessionInfo: SessionInfo) => {
101вҶ’      loadSession(sessionInfo.path);
102вҶ’      setView("list");
103вҶ’      setSelectedMessage(0);
104вҶ’      clearExpanded();
105вҶ’    },
106вҶ’    [loadSession, clearExpanded],
107вҶ’  );
108вҶ’
109вҶ’  // Auto-select newest message (last index) when messages load
110вҶ’  useEffect(() => {
111вҶ’    if (session.messages.length > 0 && view === "list") {
112вҶ’      setSelectedMessage((prev) =>
113вҶ’        prev >= session.messages.length ? session.messages.length - 1 : prev,
114вҶ’      );
115вҶ’    }
116вҶ’  }, [session.messages.length, view]);
117вҶ’
118вҶ’  // Open detail view
119вҶ’  const openDetail = useCallback((index: number) => {
120вҶ’    setSelectedMessage(index);
121вҶ’    setView("detail");
122вҶ’  }, []);
123вҶ’
124вҶ’  // -- View actions: each view registers its own expand/collapse handlers --
125вҶ’
126вҶ’  const viewActionsRef = useViewActionsRef();
127вҶ’  const { expandAll, collapseAll } = useViewActionCallbacks(viewActionsRef);
128вҶ’
129вҶ’  // Register message list expand/collapse when in list view.
130вҶ’  const listExpandAll = useCallback(() => {
131вҶ’    const claudeIndices: number[] = [];
132вҶ’    session.messages.forEach((msg, i) => {
133вҶ’      if (msg.role === "claude") claudeIndices.push(i);
134вҶ’    });
135вҶ’    expandMessages(claudeIndices);
136вҶ’  }, [session.messages, expandMessages]);
137вҶ’
138вҶ’  // Visual top = newest message = last index (display is reversed)
139вҶ’  const jumpToTop = useCallback(() => {
140вҶ’    setSelectedMessage(Math.max(session.messages.length - 1, 0));
141вҶ’  }, [session.messages.length]);
142вҶ’
143вҶ’  // Visual bottom = oldest message = index 0
144вҶ’  const jumpToBottom = useCallback(() => {
145вҶ’    setSelectedMessage(0);
146вҶ’  }, []);
147вҶ’
148вҶ’  const openDebug = useCallback(() => {
149вҶ’    if (sessionPath) {
150вҶ’      loadDebugLog(sessionPath);
151вҶ’      setView("debug");
152вҶ’    }
153вҶ’  }, [sessionPath, loadDebugLog]);
154вҶ’
155вҶ’  const openTeams = useCallback(() => {
156вҶ’    if (session.teams.length > 0) setView("team");
157вҶ’  }, [session.teams.length]);
158вҶ’
159вҶ’  const goToSessions = useCallback(() => {
160вҶ’    setView("picker");
161вҶ’  }, []);
162вҶ’
163вҶ’  const backToList = useCallback(() => {
164вҶ’    if (sessionPath) setView("list");
165вҶ’  }, [sessionPath]);
166вҶ’
167вҶ’  const toggleKeybinds = useCallback(() => {
168вҶ’    setShowKeybinds((v) => !v);
169вҶ’  }, []);
170вҶ’
171вҶ’  const selectProjectByIndex = useCallback(
172вҶ’    (index: number) => {
173вҶ’      if (index >= 0 && index < projectKeys.length) {
174вҶ’        handleSelectProject(projectKeys[index]);
175вҶ’      }
176вҶ’    },
177вҶ’    [projectKeys, handleSelectProject],
178вҶ’  );
179вҶ’
180вҶ’  // Keyboard navigation вҖ” build keyMap per view
181вҶ’  const keyMap: Record<string, () => void> = {};
182вҶ’
183вҶ’  // Sidebar-focused shortcuts (override main shortcuts when sidebar has focus)
184вҶ’  if (sidebarFocused) {
185вҶ’    const sidebarDown = () => setSidebarHighlight((i) => Math.min(i + 1, projectKeys.length - 1));
186вҶ’    const sidebarUp = () => setSidebarHighlight((i) => Math.max(i - 1, 0));
187вҶ’    keyMap["j"] = sidebarDown;
188вҶ’    keyMap["ArrowDown"] = sidebarDown;
189вҶ’    keyMap["k"] = sidebarUp;
190вҶ’    keyMap["ArrowUp"] = sidebarUp;
191вҶ’    keyMap["Enter"] = () => selectProjectByIndex(sidebarHighlight);
192вҶ’    keyMap["Escape"] = () => setSidebarFocused(false);
193вҶ’    keyMap["l"] = () => setSidebarFocused(false);
194вҶ’    keyMap["ArrowRight"] = () => setSidebarFocused(false);
195вҶ’    keyMap["?"] = toggleKeybinds;
196вҶ’  } else {
197вҶ’    switch (view) {
198вҶ’      case "list": {
199вҶ’        const listDown = () => setSelectedMessage((i) => Math.max(i - 1, 0));
200вҶ’        const listUp = () =>
201вҶ’          setSelectedMessage((i) => Math.min(i + 1, session.messages.length - 1));
202вҶ’        keyMap["j"] = listDown;
203вҶ’        keyMap["ArrowDown"] = listDown;
204вҶ’        keyMap["k"] = listUp;
205вҶ’        keyMap["ArrowUp"] = listUp;
206вҶ’        keyMap["G"] = jumpToTop;
207вҶ’        keyMap["g"] = jumpToBottom;
208вҶ’        keyMap["Tab"] = () => toggleMessage(selectedMessage);
209вҶ’        keyMap["Enter"] = () => {
210вҶ’          if (session.messages.length > 0) openDetail(selectedMessage);
211вҶ’        };
212вҶ’        keyMap["e"] = expandAll;
213вҶ’        keyMap["c"] = collapseAll;
214вҶ’        keyMap["t"] = openTeams;
215вҶ’        keyMap["d"] = openDebug;
216вҶ’        keyMap["q"] = goToSessions;
217вҶ’        keyMap["Escape"] = goToSessions;
218вҶ’        keyMap["s"] = goToSessions;
219вҶ’        keyMap["?"] = toggleKeybinds;
220вҶ’        keyMap["h"] = () => setSidebarFocused(true);
221вҶ’        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
222вҶ’        break;
223вҶ’      }
224вҶ’      case "detail":
225вҶ’        // j/k/Tab/Enter/q/Escape handled by MessageDetail's own useKeyboard
226вҶ’        keyMap["?"] = toggleKeybinds;
227вҶ’        break;
228вҶ’      case "picker": {
229вҶ’        const pickerDown = () =>
230вҶ’          setPickerSelectedIndex((i) => Math.min(i + 1, picker.sessions.length - 1));
231вҶ’        const pickerUp = () => setPickerSelectedIndex((i) => Math.max(i - 1, 0));
232вҶ’        keyMap["j"] = pickerDown;
233вҶ’        keyMap["ArrowDown"] = pickerDown;
234вҶ’        keyMap["k"] = pickerUp;
235вҶ’        keyMap["ArrowUp"] = pickerUp;
236вҶ’        keyMap["Enter"] = () => {
237вҶ’          if (picker.sessions[pickerSelectedIndex])
238вҶ’            handleSelectSession(picker.sessions[pickerSelectedIndex]);
239вҶ’        };
240вҶ’        keyMap["q"] = backToList;
241вҶ’        keyMap["Escape"] = backToList;
242вҶ’        keyMap["?"] = toggleKeybinds;
243вҶ’        keyMap["h"] = () => setSidebarFocused(true);
244вҶ’        keyMap["ArrowLeft"] = () => setSidebarFocused(true);
245вҶ’        break;
246вҶ’      }
247вҶ’      case "team":
248вҶ’        keyMap["q"] = () => setView("list");
249вҶ’        keyMap["Escape"] = () => setView("list");
250вҶ’        keyMap["?"] = toggleKeybinds;
251вҶ’        break;
252вҶ’      case "debug":
253вҶ’        keyMap["q"] = () => setView("list");
254вҶ’        keyMap["Escape"] = () => setView("list");
255вҶ’        keyMap["?"] = toggleKeybinds;
256вҶ’        break;
257вҶ’    }
258вҶ’  }
259вҶ’  useKeyboard(keyMap);
260вҶ’
261вҶ’  // Keybind bar click actions
262вҶ’  const keybindActions: Record<string, () => void> = {};
263вҶ’  if (view === "list") {
264вҶ’    keybindActions["debug"] = openDebug;
265вҶ’    keybindActions["sessions"] = goToSessions;
266вҶ’    if (session.teams.length > 0) {
267вҶ’      keybindActions["tasks"] = openTeams;
268вҶ’    }
269вҶ’  } else if (view === "picker") {
270вҶ’    keybindActions["back"] = backToList;
271вҶ’  } else if (view === "detail") {
272вҶ’    keybindActions["back"] = () => setView("list");
273вҶ’  } else if (view === "team") {
274вҶ’    keybindActions["back"] = () => setView("list");
275вҶ’  } else if (view === "debug") {
276вҶ’    keybindActions["back"] = () => setView("list");
277вҶ’  }
278вҶ’
279вҶ’  // Render the active view
280вҶ’  const renderView = () => {
281вҶ’    switch (view) {
282вҶ’      case "picker":
283вҶ’        return (
284вҶ’          <SessionPicker
285вҶ’            sessions={picker.sessions}
286вҶ’            loading={picker.loading}
287вҶ’            searchQuery={picker.searchQuery}
288вҶ’            selectedIndex={pickerSelectedIndex}
289вҶ’            onSelect={handleSelectSession}
290вҶ’            onSearchChange={picker.setSearchQuery}
291вҶ’            onSelectIndex={setPickerSelectedIndex}
292вҶ’          />
293вҶ’        );
294вҶ’
295вҶ’      case "list":
296вҶ’        if (session.loading) {
297вҶ’          return (
298вҶ’            <div className="session-loading">
