import { Box, Text } from "ink";

type ViewState = "picker" | "list" | "detail" | "team" | "debug";

interface KeyHint {
  key: string;
  label: string;
}

const pickerKeys: KeyHint[] = [
  { key: "j/k", label: "nav" },
  { key: "Enter", label: "open" },
  { key: "/", label: "search" },
  { key: "q", label: "quit" },
];

const listKeys: KeyHint[] = [
  { key: "j/k", label: "nav" },
  { key: "G/g", label: "jump" },
  { key: "Tab", label: "toggle" },
  { key: "Enter", label: "detail" },
  { key: "e/c", label: "expand" },
  { key: "d", label: "debug" },
  { key: "q", label: "sessions" },
];

const listKeysWithTeams: KeyHint[] = [
  ...listKeys.slice(0, 5),
  { key: "t", label: "tasks" },
  ...listKeys.slice(5),
];

const detailKeys: KeyHint[] = [
  { key: "j/k", label: "items" },
  { key: "Tab", label: "toggle" },
  { key: "q/Esc", label: "back" },
];

