import { Box, Text } from "ink";
import type { DisplayMessage, DisplayItem } from "../api.js";
import { formatDuration, truncate, roleColor, roleIcon, formatJson } from "../lib/format.js";
import { StatsBar, statsFromMessage } from "./StatsBar.js";

interface DetailViewProps {
  message: DisplayMessage;
  selectedItem: number;
  expandedItems: Set<number>;
  ongoing: boolean;
}

function getItemIcon(item: DisplayItem): string {
  switch (item.item_type) {
    case "Thinking":
      return "рҹ’ӯ";
    case "Output":
      return "вңҺ";
    case "ToolCall":
      return item.tool_error ? "вҡ " : "вҡҷ";
    case "Subagent":
      return "рҹӨ–";
    case "TeammateMessage":
      return "рҹ‘Ҙ";
    case "HookEvent":
      return "вҡЎ";
    default:
      return "В·";
  }
}

function getItemName(item: DisplayItem): string {
  switch (item.item_type) {
    case "Thinking":
      return "Thinking";
    case "Output":
      return "Output";
    case "ToolCall":
      return item.tool_name || "Tool";
    case "Subagent":
      return item.subagent_type || "Subagent";
    case "TeammateMessage":
      return item.team_member_name || "Teammate";
    case "HookEvent":
      return item.hook_event || "Hook";
    default:
      return item.item_type;
  }
}

function getItemSummary(item: DisplayItem): string {
  switch (item.item_type) {
    case "ToolCall":
      return item.tool_summary || "";
    case "Subagent":
      return item.subagent_desc || "";
    case "TeammateMessage":
      return item.text ? item.text.slice(0, 100) : "";
    case "Thinking":
      return item.text
        ? item.text.slice(0, 80) + (item.text.length > 80 ? "вҖҰ" : "")
        : "Content not recorded";
    case "Output":
      return item.text ? item.text.slice(0, 80) + (item.text.length > 80 ? "вҖҰ" : "") : "";
    case "HookEvent":
      return item.hook_name
        ? `${item.hook_name}${item.hook_command ? ": " + truncate(item.hook_command, 60) : ""}`
        : item.hook_command
          ? truncate(item.hook_command, 80)
          : "";
    default:
      return "";
  }
}

function formatJson(input: string): string {
  try {
    return JSON.stringify(JSON.parse(input), null, 2);
  } catch {
    return input;
  }
}

function itemColor(item: DisplayItem): string {
  switch (item.item_type) {
    case "Thinking":
      return "gray";
    case "Output":
      return "white";
    case "ToolCall":
      return item.tool_error ? "red" : "blue";
    case "Subagent":
      return "cyan";
    case "TeammateMessage":
      return "blue";
    case "HookEvent":
      return "yellow";
    default:
      return "gray";
  }
}

export function DetailView({ message, selectedItem, expandedItems, ongoing }: DetailViewProps) {
  const cols = process.stdout.columns || 80;
  const windowSize = (process.stdout.rows || 24) - 8;
  const stats = statsFromMessage(message);

  // Window around selected item
  const items = message.items;
  let start = Math.max(0, selectedItem - Math.floor(windowSize / 2));
  const end = Math.min(items.length, start + windowSize);
  if (end - start < windowSize) start = Math.max(0, end - windowSize);
  const visible = items.slice(start, end);

  return (
    <Box flexDirection="column">
      {/* Message header */}
      <Box paddingX={1} gap={1}>
        <Text bold color={roleColor(message.role)}>
          {roleIcon(message.role)} {message.role}
        </Text>
        {message.subagent_label ? <Text color="cyan">[{message.subagent_label}]</Text> : null}
        <StatsBar stats={stats} />
        {ongoing ? (
          <Text color="green" bold>
            в—Ҹ
          </Text>
        ) : null}
      </Box>

      {/* Content preview */}
      <Box paddingX={1} marginBottom={1}>
        <Text dimColor wrap="truncate">
          {truncate(message.content, cols * 2)}
        </Text>
      </Box>

      {/* Items list */}
      {items.length === 0 ? (
        <Box paddingX={1}>
          <Text dimColor>No detail items</Text>
        </Box>
      ) : (
        <Box flexDirection="column" paddingX={1}>
          {visible.map((item, i) => {
            const idx = start + i;
            const isSelected = idx === selectedItem;
            const isExpanded = expandedItems.has(idx);

            return (
              <Box key={idx} flexDirection="column">
                {/* Item header */}
                <Box>
                  <Text inverse={isSelected} bold={isSelected} color={itemColor(item)}>
                    {isSelected ? "в–ё" : " "}
                    {isExpanded ? "в–ј" : "в–¶"} {getItemIcon(item)} {getItemName(item)}
                  </Text>
                  {item.tool_summary || getItemSummary(item) ? (
                    <Text dimColor> вҖ” {truncate(getItemSummary(item), cols - 30)}</Text>
                  ) : null}
                  {item.duration_ms > 0 ? (
                    <Text dimColor> {formatDuration(item.duration_ms)}</Text>
                  ) : null}
                  {item.subagent_ongoing ? (
                    <Text color="green" bold>
                      {" "}
                      в—Ҹ
                    </Text>
                  ) : null}
                  {item.agent_id ? <Text dimColor> [{item.agent_id.slice(0, 8)}]</Text> : null}
                </Box>

                {/* Expanded body */}
                {isExpanded && <DetailItemBody item={item} cols={cols} />}
              </Box>
            );
          })}
        </Box>
      )}
    </Box>
  );
}

function DetailItemBody({ item, cols }: { item: DisplayItem; cols: number }) {
  const maxWidth = cols - 6;

  switch (item.item_type) {
    case "Thinking":
      return (
        <Box paddingLeft={4} marginBottom={1} flexDirection="column">
          <Text color="gray" wrap="wrap">
            {item.text || "Thinking content is not recorded in session logs."}
          </Text>
        </Box>
      );
    case "Output":
      return (
        <Box paddingLeft={4} marginBottom={1} flexDirection="column">
          <Text wrap="wrap">{item.text}</Text>
        </Box>
      );
    case "ToolCall":
      return (
        <Box paddingLeft={4} marginBottom={1} flexDirection="column">
          {item.tool_input && (
            <Box flexDirection="column">
              <Text bold dimColor>
                Input:
              </Text>
              <Text dimColor wrap="wrap">
                {truncate(formatJson(item.tool_input), maxWidth * 5)}
              </Text>
            </Box>
          )}
          {item.tool_result && (
            <Box flexDirection="column">
              <Text bold dimColor>
                Result:
              </Text>
              <Text color={item.tool_error ? "red" : undefined} wrap="wrap">
                {truncate(item.tool_result, maxWidth * 5)}
              </Text>
            </Box>
          )}
        </Box>
      );
    case "Subagent":
      return (
        <Box paddingLeft={4} marginBottom={1} flexDirection="column">
          {item.agent_id && (
            <Box>
              <Text bold dimColor>
                ID:{" "}
              </Text>
              <Text dimColor>{item.agent_id}</Text>
            </Box>
          )}
          {item.subagent_desc && (
            <Box>
              <Text bold dimColor>
                Desc:{" "}
              </Text>
              <Text>{item.subagent_desc}</Text>
            </Box>
          )}
          {item.subagent_prompt && (
            <Box flexDirection="column">
              <Text bold dimColor>
                Prompt:
              </Text>
              <Text wrap="wrap">{truncate(item.subagent_prompt, maxWidth * 3)}</Text>
            </Box>
          )}
          {item.text && (
            <Box flexDirection="column">
              <Text bold dimColor>
                Content:
              </Text>
              <Text wrap="wrap">{truncate(item.text, maxWidth * 3)}</Text>
            </Box>
          )}
        </Box>
      );
    case "TeammateMessage":
      return (
        <Box paddingLeft={4} marginBottom={1}>
          <Text wrap="wrap">{item.text}</Text>
        </Box>
      );
    case "HookEvent":
      return (
        <Box paddingLeft={4} marginBottom={1} flexDirection="column">
          <Box>
            <Text bold dimColor>
              Hook:{" "}
            </Text>
            <Text>
              {item.hook_event}: {item.hook_name}
            </Text>
          </Box>
          {item.hook_command && (
            <Box>
              <Text bold dimColor>
                Cmd:{" "}
              </Text>
              <Text dimColor>{item.hook_command}</Text>
            </Box>
          )}
        </Box>
      );
    default:
      return (
        <Box paddingLeft={4} marginBottom={1}>
          <Text wrap="wrap">{item.text}</Text>
        </Box>
      );
  }
}

import { Box, Text } from "ink";
import type { DisplayMessage } from "../api.js";
import { formatTokens, formatDuration } from "../../../shared/format.js";

export interface Stats {
  tokens: number;
  toolCount: number;
  thinkingCount: number;
  outputCount: number;
  durationMs: number;
  agentCount: number;
  spawnCount: number;
}

export function statsFromMessage(msg: DisplayMessage): Stats {
  const agentCount = msg.items.filter(
    (it) => it.item_type === "Subagent" || it.subagent_messages.length > 0,
  ).length;
  return {
    tokens: msg.tokens_raw,
    toolCount: msg.tool_call_count,
    thinkingCount: msg.thinking_count,
    outputCount: msg.output_count,
    durationMs: msg.duration_ms,
    agentCount,
    spawnCount: msg.teammate_spawns,
  };
}

function hasAny(s: Stats): boolean {
  return (
    s.tokens > 0 ||
    s.toolCount > 0 ||
    s.thinkingCount > 0 ||
    s.outputCount > 0 ||
    s.durationMs > 0 ||
    s.agentCount > 0 ||
    s.spawnCount > 0
  );
}

export function StatsBar({ stats }: { stats: Stats }) {
  if (!hasAny(stats)) return null;

  return (
    <Box gap={1}>
      {stats.tokens > 0 && (
        <Text dimColor color={stats.tokens > 150000 ? "yellow" : undefined}>
          {formatTokens(stats.tokens)} tok
        </Text>
      )}
      {stats.toolCount > 0 && (
        <Text dimColor color="blue">
          вҡҷ{stats.toolCount}
        </Text>
      )}
      {stats.thinkingCount > 0 && (
        <Text dimColor color="gray">
          рҹ’ӯ{stats.thinkingCount}
        </Text>
      )}
      {stats.outputCount > 0 && <Text dimColor>вңҺ{stats.outputCount}</Text>}
      {stats.durationMs > 0 && <Text dimColor>{formatDuration(stats.durationMs)}</Text>}
      {stats.agentCount > 0 && (
        <Text dimColor color="cyan">
          рҹӨ–{stats.agentCount}
        </Text>
      )}
      {stats.spawnCount > 0 && <Text dimColor>вҶ—{stats.spawnCount}</Text>}
    </Box>
  );
}

import { useMemo } from "react";
import { Box, Text } from "ink";
import type { DisplayMessage, SessionMeta, SessionTotals } from "../api.js";
import { formatTokens, formatCost } from "../../../shared/format.js";

interface InfoBarProps {
  meta: SessionMeta;
  messages: DisplayMessage[];
  sessionTotals: SessionTotals;
  sessionPath: string;
  ongoing: boolean;
}

function shortPath(cwd: string): string {
  if (!cwd) return "";
  const parts = cwd.split("/").filter(Boolean);
  return parts[parts.length - 1] ?? cwd;
}

function shortMode(mode: string): string {
  switch (mode) {
    case "acceptEdits":
      return "auto-edit";
    case "bypassPermissions":
      return "yolo";
    case "plan":
      return "plan";
    default:
      return mode;
  }
}

function contextPercent(msgs: DisplayMessage[]): number {
  const contextWindowSize = 1_000_000;
  for (let i = msgs.length - 1; i >= 0; i--) {
    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
      return Math.min(Math.floor((msgs[i].context_tokens * 100) / contextWindowSize), 100);
    }
  }
  return -1;
}

function contextColor(pct: number): string {
  if (pct < 50) return "green";
  if (pct < 80) return "yellow";
  return "red";
}

function modeColor(mode: string): string {
  switch (mode) {
    case "bypassPermissions":
      return "red";
    case "acceptEdits":
      return "magenta";
    case "plan":
      return "green";
    default:
      return "white";
  }
}

export function InfoBar({ meta, messages, sessionTotals, sessionPath, ongoing }: InfoBarProps) {
  const projectName = shortPath(meta.cwd);
  const sessionId = sessionPath.split("/").pop()?.replace(".jsonl", "") || "";
  const branch = meta.git_branch;
  const mode = meta.permission_mode;
  const ctxPct = useMemo(() => contextPercent(messages), [messages]);

  return (
    <Box paddingX={1} gap={1}>
      {projectName ? (
        <Text bold color="cyan">
          {projectName}
        </Text>
      ) : null}

      {sessionId ? <Text dimColor>{sessionId.slice(0, 8)}</Text> : null}

      {branch ? <Text color="magenta">{branch}</Text> : null}

      {mode && mode !== "default" ? (
        <Text color={modeColor(mode)} bold>
          [{shortMode(mode)}]
        </Text>
      ) : null}

      {ctxPct >= 0 ? <Text color={contextColor(ctxPct)}>ctx {ctxPct}%</Text> : null}

      {sessionTotals.total_tokens > 0 ? (
        <Text dimColor>{formatTokens(sessionTotals.total_tokens)} tok</Text>
      ) : null}

      {sessionTotals.cost_usd > 0 ? (
        <Text color="yellow">{formatCost(sessionTotals.cost_usd)}</Text>
      ) : null}

      {ongoing ? (
        <Text color="green" bold>
          в—Ҹ active
        </Text>
      ) : null}
    </Box>
  );
}

import { Box, Text } from "ink";
import type { DebugEntry } from "../api.js";
import { truncate } from "../../../shared/format.js";

interface DebugViewerProps {
  entries: DebugEntry[];
  selectedIndex: number;
}

function levelColor(level: string): string {
  switch (level.toLowerCase()) {
    case "error":
      return "red";
    case "warn":
      return "yellow";
    case "info":
      return "blue";
    case "debug":
      return "gray";
    default:
      return "white";
  }
}

export function DebugViewer({ entries, selectedIndex }: DebugViewerProps) {
  const cols = process.stdout.columns || 80;
  const windowSize = (process.stdout.rows || 24) - 4;

  let start = Math.max(0, selectedIndex - Math.floor(windowSize / 2));
  const end = Math.min(entries.length, start + windowSize);
  if (end - start < windowSize) start = Math.max(0, end - windowSize);
  const visible = entries.slice(start, end);

  if (entries.length === 0) {
    return (
      <Box paddingX={1}>
        <Text dimColor>No debug entries</Text>
      </Box>
    );
  }

  return (
    <Box flexDirection="column" paddingX={1}>
      <Box marginBottom={1}>
        <Text bold>Debug Log ({entries.length})</Text>
      </Box>

      {visible.map((entry, i) => {
        const idx = start + i;
        const isSelected = idx === selectedIndex;
        const ts = entry.timestamp ? entry.timestamp.split("T")[1]?.split(".")[0] || "" : "";

        return (
          <Box key={idx}>
            <Text inverse={isSelected} bold={isSelected}>
              {isSelected ? "в–ё" : " "}
            </Text>
            <Text dimColor> {ts} </Text>
            <Text color={levelColor(entry.level)} bold>
              {entry.level.toUpperCase().padEnd(5)}{" "}
            </Text>
            {entry.category ? <Text color="cyan">[{entry.category}] </Text> : null}
            <Text dimColor={!isSelected}>{truncate(entry.message, cols - 30)}</Text>
            {entry.count > 1 ? <Text color="yellow"> x{entry.count}</Text> : null}
          </Box>
        );
      })}
    </Box>
  );
}

